      'mensagens-internas-tecnicos': 'open-mensagens-internas-tecnicos',
      'tecnicos-internos': 'open-tecnicos-internos',
      'tecnicos-externos': 'open-tecnicos-externos',
      'alerta-mensagens': 'open-alerta-mensagens',
