  // Componentes do Sistema de Comunicação Interna
  const ComunicacaoEnviarMensagem = ({ 
    gestores, 
    tecnicos, 
    tiposGestores,
    onEnviarMensagem,
    safeT 
  }: { 
    gestores: Gestor[]
    tecnicos: Tecnico[]
    tiposGestores: TipoGestor[]
    onEnviarMensagem: (mensagem: Omit<MensagemComunicacao, 'id' | 'dataEnvio' | 'lida'>) => void
    safeT: any
  }) => {
    // Remetente: Apenas Gestores
    const [remetenteArea, setRemetenteArea] = useState<string>('assistencia-tecnica')
    const [remetenteId, setRemetenteId] = useState('')
    const [gestorSelecionado, setGestorSelecionado] = useState<Gestor | null>(null)
    
    // Destinatário: Técnicos
    const [destinatarioTipo, setDestinatarioTipo] = useState<'interno' | 'externo' | 'armazem' | 'todos'>('todos')
    const [destinatarioId, setDestinatarioId] = useState('')
    
    const [assunto, setAssunto] = useState('')
    const [mensagem, setMensagem] = useState('')
    const [arquivos, setArquivos] = useState<Array<{ nome: string, tipo: string, dados: string }>>([])
    const [imagens, setImagens] = useState<Array<{ nome: string, dados: string }>>([])

    // Gestores disponíveis - quando seleciona um gestor, mostra todos da mesma área
    const gestoresDisponiveis = React.useMemo(() => {
      if (gestorSelecionado) {
        // Se um gestor foi selecionado, mostrar todos os gestores da mesma área
        return gestores.filter(g => g.area === gestorSelecionado.area)
      } else if (remetenteArea) {
        // Se apenas a área foi selecionada, mostrar gestores dessa área
        return gestores.filter(g => g.area === remetenteArea)
      }
      return gestores
    }, [remetenteArea, gestores, gestorSelecionado])

    // Técnicos disponíveis - quando seleciona o tipo, mostra todos desse tipo
    const tecnicosDisponiveis = React.useMemo(() => {
      if (destinatarioTipo === 'todos') {
        return tecnicos
      } else if (destinatarioTipo === 'armazem') {
        return tecnicos.filter(t => t.type === 'armazem')
      } else if (destinatarioTipo === 'interno') {
        return tecnicos.filter(t => t.type === 'internal')
      } else if (destinatarioTipo === 'externo') {
        return tecnicos.filter(t => t.type === 'external')
      }
      return tecnicos
    }, [destinatarioTipo, tecnicos])

    const handleArquivoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const files = e.target.files
      if (!files) return

      Array.from(files).forEach(file => {
        const reader = new FileReader()
        reader.onload = (event) => {
          const dados = event.target?.result as string
          setArquivos(prev => [...prev, {
            nome: file.name,
            tipo: file.type,
            dados: dados
          }])
        }
        reader.readAsDataURL(file)
      })
    }

    const handleImagemChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const files = e.target.files
      if (!files) return

      Array.from(files).forEach(file => {
        if (!file.type.startsWith('image/')) {
          alert(safeT?.selectImage || 'Por favor, selecione apenas imagens')
          return
        }
        const reader = new FileReader()
        reader.onload = (event) => {
          const dados = event.target?.result as string
          setImagens(prev => [...prev, {
            nome: file.name,
            dados: dados
          }])
        }
        reader.readAsDataURL(file)
      })
    }

    const removerArquivo = (index: number) => {
      setArquivos(prev => prev.filter((_, i) => i !== index))
    }

    const removerImagem = (index: number) => {
      setImagens(prev => prev.filter((_, i) => i !== index))
    }

    const handleEnviar = () => {
      if (!assunto.trim() || !mensagem.trim()) {
        alert(safeT?.preencherTodosCampos || 'Por favor, preencha todos os campos')
        return
      }

      // VALIDAÇÃO: Gestor remetente deve ser selecionado
      if (!remetenteId) {
        alert(safeT?.selecionarGestor || 'Por favor, selecione um gestor remetente')
        return
      }

      const gestorSelecionadoObj = gestores.find(g => g.id === remetenteId) || gestorSelecionado
      if (!gestorSelecionadoObj) {
        alert(safeT?.erroSelecao || 'Erro ao selecionar gestor')
        return
      }

      // Usar o gestor selecionado do estado ou o encontrado
      const gestorSelecionadoFinal = gestorSelecionadoObj

      // Mapear área do gestor para classe (usar o tipo de gestor selecionado)
      const tipoGestor = tiposGestores.find(t => t.id === gestorSelecionadoFinal.area || t.id === remetenteArea)
      const remetenteClasse = gestorSelecionadoFinal.area === 'assistencia-tecnica' ? 'gestor' : 
                              gestorSelecionadoFinal.area === 'industrial' ? 'gestor-industrial' : 
                              'armazem'

      if (destinatarioTipo === 'todos') {
        // Enviar para todos os técnicos
        tecnicos.forEach(tecnico => {
          const tecnicoClasse = tecnico.type === 'internal' ? 'tecnico-interno' :
                               tecnico.type === 'external' ? 'tecnico-externo' :
                               'armazem'
          
          onEnviarMensagem({
            remetenteId: remetenteId,
            remetenteNome: gestorSelecionadoObj.name,
            remetenteTipo: 'gestor',
            remetenteClasse: remetenteClasse as any,
            remetenteArea: (gestorSelecionadoObj.area || remetenteArea) as 'assistencia-tecnica' | 'industrial' | 'armazem' | undefined,
            destinatarioId: tecnico.id,
            destinatarioNome: tecnico.name,
            destinatarioTipo: 'tecnico',
            destinatarioClasse: tecnicoClasse as any,
            destinatarioTipoTecnico: tecnico.type === 'internal' ? 'interno' : tecnico.type === 'external' ? 'externo' : 'armazem',
            assunto,
            mensagem,
            arquivos: arquivos.length > 0 ? arquivos : undefined,
            imagens: imagens.length > 0 ? imagens : undefined
          })
        })
      } else if (destinatarioTipo === 'armazem') {
        // Enviar para armazém
        onEnviarMensagem({
          remetenteId: remetenteId,
          remetenteNome: gestorSelecionadoObj.name,
          remetenteTipo: 'gestor',
          remetenteClasse: remetenteClasse as any,
          remetenteArea: (gestorSelecionadoObj.area || remetenteArea) as 'assistencia-tecnica' | 'industrial' | 'armazem' | undefined,
          destinatarioId: 'armazem',
          destinatarioNome: safeT?.armazem || 'Armazém',
          destinatarioTipo: 'armazem',
          destinatarioClasse: 'armazem',
          destinatarioTipoTecnico: 'armazem',
          assunto,
          mensagem,
          arquivos: arquivos.length > 0 ? arquivos : undefined,
          imagens: imagens.length > 0 ? imagens : undefined
        })
      } else if (destinatarioId) {
        // Enviar para técnico específico
        const tecnicoSelecionado = tecnicos.find(t => t.id === destinatarioId)
        if (!tecnicoSelecionado) {
          alert(safeT?.selecionarTecnico || 'Por favor, selecione um técnico')
          return
        }

        const tecnicoClasse = tecnicoSelecionado.type === 'internal' ? 'tecnico-interno' :
                             tecnicoSelecionado.type === 'external' ? 'tecnico-externo' :
                             'armazem'

        onEnviarMensagem({
          remetenteId: remetenteId,
          remetenteNome: gestorSelecionadoObj.name,
          remetenteTipo: 'gestor',
          remetenteClasse: remetenteClasse as any,
          remetenteArea: (gestorSelecionadoObj.area || remetenteArea) as 'assistencia-tecnica' | 'industrial' | 'armazem' | undefined,
          destinatarioId: destinatarioId,
          destinatarioNome: tecnicoSelecionado.name,
          destinatarioTipo: 'tecnico',
          destinatarioClasse: tecnicoClasse as any,
            destinatarioTipoTecnico: tecnicoSelecionado.type === 'internal' ? 'interno' : tecnicoSelecionado.type === 'external' ? 'externo' : 'armazem',
          assunto,
          mensagem,
          arquivos: arquivos.length > 0 ? arquivos : undefined,
          imagens: imagens.length > 0 ? imagens : undefined
        })
      } else {
        alert(safeT?.selecionarTecnico || 'Por favor, selecione um técnico ou "Todos os Técnicos"')
        return
      }

      // Limpar formulário
      setAssunto('')
      setMensagem('')
      setDestinatarioId('')
      setArquivos([])
      setImagens([])
      alert(safeT?.mensagemEnviada || 'Mensagem enviada com sucesso!')
    }

    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
        <h3 style={{ color: '#66b3ff', marginBottom: '10px', fontSize: '18px', textAlign: 'center' }}>
          {safeT?.novaMensagem || 'Nova Mensagem'}
        </h3>

        {/* Remetente: Apenas Gestores */}
        <div>
          <label style={{ color: '#66b3ff', display: 'block', marginBottom: '8px', fontWeight: 'bold' }}>
            {safeT?.remetente || 'GESTOR (REMETENTE)'}:
          </label>
          
          {/* Setor do Gestor */}
          <div style={{ marginBottom: '10px' }}>
            <label style={{ color: '#ccc', display: 'block', marginBottom: '5px', fontSize: '13px' }}>
              {safeT?.areaGestor || 'Setor do Gestor'}:
            </label>
            <select
              value={remetenteArea}
              onChange={(e) => {
                setRemetenteArea(e.target.value)
                setRemetenteId('') // Resetar gestor quando mudar área
                setGestorSelecionado(null)
              }}
              style={{
                padding: '10px',
                backgroundColor: '#222222',
                border: '2px solid rgba(0, 255, 0, 0.3)',
                borderRadius: '6px',
                color: '#fff',
                width: '100%',
                fontSize: '14px',
                cursor: 'pointer'
              }}
            >
              {tiposGestores.sort((a, b) => a.ordem - b.ordem).map(tipo => (
                <option key={tipo.id} value={tipo.id}>{tipo.icone} {tipo.nome}</option>
              ))}
            </select>
          </div>

          {/* Gestor Selecionado */}
          <div>
            <label style={{ color: '#ccc', display: 'block', marginBottom: '5px', fontSize: '13px' }}>
              {safeT?.selecionarGestor || 'Selecionar Gestor'}:
            </label>
            <select
              value={remetenteId}
              onChange={(e) => {
                const gestorId = e.target.value
                setRemetenteId(gestorId)
                // Quando selecionar um gestor, atualizar a área e mostrar todos os gestores da mesma área
                if (gestorId) {
                  const gestorSelecionado = gestores.find(g => g.id === gestorId)
                  if (gestorSelecionado) {
                    setGestorSelecionado(gestorSelecionado)
                    setRemetenteArea(gestorSelecionado.area)
                  }
                } else {
                  setGestorSelecionado(null)
                }
              }}
              style={{
                padding: '10px',
                backgroundColor: '#222222',
                border: '2px solid rgba(0, 255, 0, 0.3)',
                borderRadius: '6px',
                color: '#fff',
                width: '100%',
                fontSize: '14px',
                cursor: 'pointer'
              }}
            >
              <option value="">{safeT?.selecionarGestor || 'Selecionar Gestor'}</option>
              {gestoresDisponiveis.map(g => (
                <option key={g.id} value={g.id}>
                  {g.name}
                </option>
              ))}
            </select>
            {gestorSelecionado && gestoresDisponiveis.length > 1 && (
              <div style={{ 
                marginTop: '10px', 
                padding: '10px', 
                backgroundColor: 'rgba(0, 100, 255, 0.1)', 
                borderRadius: '6px',
                border: '1px solid rgba(0, 255, 0, 0.3)'
              }}>
                <p style={{ margin: 0, fontSize: '12px', color: '#66b3ff' }}>
                  📋 <strong>Gestores da mesma área ({gestoresDisponiveis.length}):</strong>
                </p>
                <div style={{ marginTop: '8px', display: 'flex', flexDirection: 'column', gap: '5px' }}>
                  {gestoresDisponiveis.map(g => (
                    <div key={g.id} style={{ 
                      padding: '6px 10px', 
                      backgroundColor: g.id === remetenteId ? 'rgba(0, 100, 255, 0.2)' : '#141414',
                      borderRadius: '4px',
                      fontSize: '12px',
                      border: g.id === remetenteId ? '1px solid rgba(0, 100, 255, 0.5)' : '1px solid rgba(0, 100, 255, 0.2)'
                    }}>
                      {g.id === remetenteId ? '✓ ' : ''}{g.name} {g.email ? `(${g.email})` : ''}
                    </div>
                  ))}
                </div>
              </div>
            )}
            {gestoresDisponiveis.length === 0 && (
              <p style={{ color: '#ff6b6b', fontSize: '12px', marginTop: '5px' }}>
                {safeT?.nenhumGestorArea || 'Nenhum gestor cadastrado neste setor'}
              </p>
            )}
          </div>
        </div>

        {/* Destinatário: Técnicos */}
        <div>
          <label style={{ color: '#66b3ff', display: 'block', marginBottom: '8px', fontWeight: 'bold' }}>
            {safeT?.destinatario || 'TÉCNICO (DESTINATÁRIO)'}:
          </label>
          
          {/* Tipo de Técnico */}
          <div style={{ marginBottom: '10px' }}>
            <label style={{ color: '#ccc', display: 'block', marginBottom: '5px', fontSize: '13px' }}>
              {safeT?.tipoTecnico || 'Tipo de Técnico'}:
            </label>
            <select
              value={destinatarioTipo}
              onChange={(e) => {
                setDestinatarioTipo(e.target.value as 'interno' | 'externo' | 'armazem' | 'todos')
                setDestinatarioId('') // Resetar técnico quando mudar tipo
              }}
              style={{
                padding: '10px',
                backgroundColor: '#222222',
                border: '2px solid rgba(0, 255, 0, 0.3)',
                borderRadius: '6px',
                color: '#fff',
                width: '100%',
                fontSize: '14px',
                cursor: 'pointer'
              }}
            >
              <option value="todos">{safeT?.todosTecnicos || 'Todos os Técnicos'} ({tecnicos.length})</option>
              <option value="interno">{safeT?.tecnicoInterno || 'Técnico Interno'} ({tecnicos.filter(t => t.type === 'internal').length})</option>
              <option value="externo">{safeT?.tecnicoExterno || 'Técnico Externo'} ({tecnicos.filter(t => t.type === 'external').length})</option>
              <option value="armazem">{safeT?.tecnicoArmazem || 'Técnico Armazém'}</option>
            </select>
          </div>

          {/* Técnico Selecionado (se não for "Todos") */}
          {destinatarioTipo !== 'todos' && destinatarioTipo !== 'armazem' && (
            <div>
              <label style={{ color: '#ccc', display: 'block', marginBottom: '5px', fontSize: '13px' }}>
                {safeT?.selecionarTecnico || 'Selecionar Técnico'}:
              </label>
              <select
                value={destinatarioId}
                onChange={(e) => setDestinatarioId(e.target.value)}
                style={{
                  padding: '10px',
                  backgroundColor: '#222222',
                  border: '2px solid rgba(0, 255, 0, 0.3)',
                  borderRadius: '6px',
                  color: '#fff',
                  width: '100%',
                  fontSize: '14px',
                  cursor: 'pointer'
                }}
              >
                <option value="">{safeT?.selecionarTecnico || 'Selecionar Técnico'}</option>
                {tecnicosDisponiveis.map(t => (
                  <option key={t.id} value={t.id}>
                    {t.name}
                  </option>
                ))}
              </select>
              {tecnicosDisponiveis.length > 0 && (
                <div style={{ 
                  marginTop: '10px', 
                  padding: '10px', 
                  backgroundColor: destinatarioTipo === 'interno' ? 'rgba(0, 255, 0, 0.1)' : 'rgba(255, 165, 0, 0.1)', 
                  borderRadius: '6px',
                  border: `1px solid ${destinatarioTipo === 'interno' ? 'rgba(0, 255, 0, 0.3)' : 'rgba(255, 165, 0, 0.3)'}`
                }}>
                  <p style={{ margin: 0, fontSize: '12px', color: destinatarioTipo === 'interno' ? '#00ff00' : '#ffaa00' }}>
                    📋 <strong>Técnicos {destinatarioTipo === 'interno' ? 'Internos' : 'Externos'} disponíveis ({tecnicosDisponiveis.length}):</strong>
                  </p>
                  <div style={{ marginTop: '8px', display: 'flex', flexDirection: 'column', gap: '5px' }}>
                    {tecnicosDisponiveis.map(t => (
                      <div key={t.id} style={{ 
                        padding: '6px 10px', 
                        backgroundColor: t.id === destinatarioId ? (destinatarioTipo === 'interno' ? 'rgba(0, 255, 0, 0.2)' : 'rgba(255, 165, 0, 0.2)') : '#141414',
                        borderRadius: '4px',
                        fontSize: '12px',
                        border: t.id === destinatarioId ? `1px solid ${destinatarioTipo === 'interno' ? 'rgba(0, 255, 0, 0.5)' : 'rgba(255, 165, 0, 0.5)'}` : `1px solid ${destinatarioTipo === 'interno' ? 'rgba(0, 255, 0, 0.2)' : 'rgba(255, 165, 0, 0.2)'}`
                      }}>
                        {t.id === destinatarioId ? '✓ ' : ''}{t.name} {t.email ? `(${t.email})` : ''}
                      </div>
                    ))}
                  </div>
                </div>
              )}
              {tecnicosDisponiveis.length === 0 && (
                <p style={{ color: '#ff6b6b', fontSize: '12px', marginTop: '5px' }}>
                  {safeT?.nenhumTecnicoTipo || 'Nenhum técnico cadastrado deste tipo'}
                </p>
              )}
            </div>
          )}
          {destinatarioTipo === 'armazem' && (
            <div style={{ padding: '10px', backgroundColor: '#222222', borderRadius: '6px', color: '#ccc', textAlign: 'center' }}>
              {safeT?.armazem || 'Armazém'}
            </div>
          )}
        </div>

        {/* Assunto */}
        <div>
          <label style={{ color: '#ccc', display: 'block', marginBottom: '8px' }}>
            {safeT?.assunto || 'Assunto'}:
          </label>
          <input
            type="text"
            value={assunto}
            onChange={(e) => setAssunto(e.target.value)}
            placeholder={safeT?.assunto || 'Assunto'}
            style={{
              padding: '10px',
              backgroundColor: '#222222',
              border: '1px solid rgba(0, 255, 0, 0.3)',
              borderRadius: '4px',
              color: '#fff',
              width: '100%'
            }}
          />
        </div>
      </div>
    )
  }

  const ComunicacaoMensagensRecebidas = ({
    mensagens,
    filtro,
    onFiltroChange,
    onMarcarComoLida,
    onExcluir,
    safeT
  }: {
    mensagens: MensagemComunicacao[]
    filtro: 'todas' | 'nao-lidas' | 'lidas'
    onFiltroChange: (filtro: 'todas' | 'nao-lidas' | 'lidas') => void
    onMarcarComoLida: (id: string) => void
    onExcluir: (id: string) => void
    safeT: any
  }) => {
    const mensagensFiltradas = React.useMemo(() => {
      if (filtro === 'nao-lidas') return mensagens.filter(m => !m.lida)
      if (filtro === 'lidas') return mensagens.filter(m => m.lida)
      return mensagens
    }, [mensagens, filtro])

    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <h3 style={{ color: '#66b3ff', margin: 0 }}>
            {safeT?.mensagensRecebidas || 'Mensagens Recebidas'}
          </h3>
          <select
            value={filtro}
            onChange={(e) => onFiltroChange(e.target.value as any)}
            style={{
              padding: '8px',
              backgroundColor: '#222222',
              border: '1px solid rgba(0, 255, 0, 0.3)',
              borderRadius: '4px',
              color: '#fff'
            }}
          >
            <option value="todas">{safeT?.todas || 'Todas'}</option>
            <option value="nao-lidas">{safeT?.apenasNaoLidas || 'Apenas Não Lidas'}</option>
            <option value="lidas">{safeT?.apenasLidas || 'Apenas Lidas'}</option>
          </select>
        </div>

        {mensagensFiltradas.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '40px', color: '#999' }}>
            <p>{safeT?.nenhumaMensagem || 'Nenhuma mensagem'}</p>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            {mensagensFiltradas.map(mensagem => (
              <div
                key={mensagem.id}
                style={{
                  padding: '20px',
                  backgroundColor: mensagem.lida ? '#141414' : 'rgba(0, 100, 255, 0.1)',
                  border: `2px solid ${mensagem.lida ? 'rgba(0, 100, 255, 0.2)' : '#66b3ff'}`,
                  borderRadius: '8px',
                  position: 'relative'
                }}
              >
                {!mensagem.lida && (
                  <span style={{
                    position: 'absolute',
                    top: '10px',
                    right: '10px',
                    backgroundColor: '#ff4444',
                    color: '#fff',
                    padding: '4px 8px',
                    borderRadius: '4px',
                    fontSize: '11px',
                    fontWeight: 'bold'
                  }}>
                    {safeT?.naoLida || 'Não Lida'}
                  </span>
                )}
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                  <div>
                    <strong style={{ color: '#66b3ff' }}>{mensagem.assunto}</strong>
                    <p style={{ color: '#ccc', fontSize: '12px', margin: '5px 0 0 0' }}>
                      {safeT?.remetente || 'De'}: {mensagem.remetenteNome} ({mensagem.remetenteTipo})
                    </p>
                  </div>
                  <div style={{ textAlign: 'right', color: '#999', fontSize: '12px' }}>
                    {new Date(mensagem.dataEnvio).toLocaleString('pt-BR')}
                  </div>
                </div>
                <p style={{ color: '#fff', marginBottom: '15px', whiteSpace: 'pre-wrap' }}>
                  {mensagem.mensagem}
                </p>
                
                {/* Exibir Arquivos Anexados */}
                {mensagem.arquivos && mensagem.arquivos.length > 0 && (
                  <div style={{ marginBottom: '15px' }}>
                    <strong style={{ color: '#66b3ff', fontSize: '13px', display: 'block', marginBottom: '8px' }}>
                      {safeT?.arquivosAnexados || 'Arquivos Anexados'}:
                    </strong>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '5px' }}>
                      {mensagem.arquivos.map((arquivo, index) => (
                        <div key={index} style={{
                          display: 'flex',
                          alignItems: 'center',
                          gap: '10px',
                          padding: '8px',
                          backgroundColor: '#141414',
                          borderRadius: '4px',
                          border: '1px solid rgba(0, 100, 255, 0.2)'
                        }}>
                          <span style={{ color: '#ccc', fontSize: '13px' }}>📎 {arquivo.nome}</span>
                          <a
                            href={arquivo.dados}
                            download={arquivo.nome}
                            style={{
                              padding: '4px 8px',
                              backgroundColor: 'rgba(0, 100, 255, 0.2)',
                              border: '1px solid rgba(0, 100, 255, 0.4)',
                              borderRadius: '4px',
                              color: '#66b3ff',
                              textDecoration: 'none',
                              fontSize: '12px',
                              cursor: 'pointer'
                            }}
                          >
                            {safeT?.baixar || 'Baixar'}
                          </a>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Exibir Imagens Anexadas */}
                {mensagem.imagens && mensagem.imagens.length > 0 && (
                  <div style={{ marginBottom: '15px' }}>
                    <strong style={{ color: '#66b3ff', fontSize: '13px', display: 'block', marginBottom: '8px' }}>
                      {safeT?.imagensAnexadas || 'Imagens Anexadas'}:
                    </strong>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(150px, 1fr))', gap: '10px' }}>
                      {mensagem.imagens.map((imagem, index) => (
                        <div key={index} style={{ position: 'relative' }}>
                          <img
                            src={imagem.dados}
                            alt={imagem.nome}
                            style={{
                              width: '100%',
                              height: '150px',
                              objectFit: 'cover',
                              borderRadius: '6px',
                              border: '2px solid rgba(0, 255, 0, 0.3)',
                              cursor: 'pointer'
                            }}
                            onClick={() => window.open(imagem.dados, '_blank')}
                            title={imagem.nome}
                          />
                        </div>
                      ))}
                    </div>
                  </div>
                )}
                <div style={{ display: 'flex', gap: '10px' }}>
                  {!mensagem.lida && (
                    <button
                      onClick={() => onMarcarComoLida(mensagem.id)}
                      style={{
                        padding: '6px 12px',
                        backgroundColor: 'rgba(0, 100, 255, 0.2)',
                        border: '1px solid #66b3ff',
                        borderRadius: '4px',
                        color: '#66b3ff',
                        cursor: 'pointer',
                        fontSize: '12px'
                      }}
                    >
                      {safeT?.marcarComoLida || 'Marcar como Lida'}
                    </button>
                  )}
                  <button
                    onClick={() => onExcluir(mensagem.id)}
                    style={{
                      padding: '6px 12px',
                      backgroundColor: 'rgba(255, 68, 68, 0.2)',
                      border: '1px solid #ff4444',
                      borderRadius: '4px',
                      color: '#ff4444',
                      cursor: 'pointer',
                      fontSize: '12px'
                    }}
                  >
                    {safeT?.excluirMensagem || 'Excluir'}
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    )
  }

  const ComunicacaoTecnicoEnviarMensagem = ({
    tecnicoId,
    tecnicoNome,
    tecnicoTipo,
    gestores,
    onEnviarMensagem,
    safeT
  }: {
    tecnicoId: string
    tecnicoNome: string
    tecnicoTipo: 'tecnico-interno' | 'tecnico-externo'
    gestores: Gestor[]
    onEnviarMensagem: (mensagem: Omit<MensagemComunicacao, 'id' | 'dataEnvio' | 'lida'>) => void
    safeT: any
  }) => {
    const [tipoDestinatario, setTipoDestinatario] = useState<'gestor' | 'armazem'>('gestor')
    const [classeDestinatario, setClasseDestinatario] = useState<'todos-gestores' | 'todos-gestores-industrial'>('todos-gestores')
    const [destinatarioId, setDestinatarioId] = useState('')
    const [assunto, setAssunto] = useState('')
    const [mensagem, setMensagem] = useState('')

    const destinatariosDisponiveis = React.useMemo(() => {
      if (tipoDestinatario === 'gestor') {
        if (classeDestinatario === 'todos-gestores-industrial') {
          return gestores.filter(g => g.area === 'industrial').map(g => ({ id: g.id, nome: g.name, classe: 'gestor-industrial' as const }))
        } else {
          return gestores.filter(g => g.area === 'assistencia-tecnica').map(g => ({ id: g.id, nome: g.name, classe: 'gestor' as const }))
        }
      }
      return []
    }, [tipoDestinatario, classeDestinatario, gestores])

    const handleEnviar = () => {
      if (!assunto.trim() || !mensagem.trim()) {
        alert(safeT?.preencherTodosCampos || 'Por favor, preencha todos os campos')
        return
      }

      if (tipoDestinatario === 'armazem') {
        onEnviarMensagem({
          remetenteId: tecnicoId,
          remetenteNome: tecnicoNome,
          remetenteTipo: 'tecnico',
          remetenteClasse: tecnicoTipo,
          destinatarioId: 'armazem',
          destinatarioNome: safeT?.armazem || 'Armazém',
          destinatarioTipo: 'armazem',
          destinatarioClasse: 'armazem',
          assunto,
          mensagem
        })
      } else if (classeDestinatario.startsWith('todos-')) {
        onEnviarMensagem({
          remetenteId: tecnicoId,
          remetenteNome: tecnicoNome,
          remetenteTipo: 'tecnico',
          remetenteClasse: tecnicoTipo,
          destinatarioId: classeDestinatario,
          destinatarioNome: classeDestinatario,
          destinatarioTipo: 'gestor',
          destinatarioClasse: classeDestinatario as any,
          assunto,
          mensagem
        })
      } else if (destinatarioId) {
        const destinatario = destinatariosDisponiveis.find(d => d.id === destinatarioId)
        onEnviarMensagem({
          remetenteId: tecnicoId,
          remetenteNome: tecnicoNome,
          remetenteTipo: 'tecnico',
          remetenteClasse: tecnicoTipo,
          destinatarioId,
          destinatarioNome: destinatario?.nome || '',
          destinatarioTipo: 'gestor',
          destinatarioClasse: destinatario?.classe || 'gestor',
          assunto,
          mensagem
        })
      } else {
        alert(safeT?.selecionarDestinatarioObrigatorio || 'Por favor, selecione um destinatário')
        return
      }

      // Limpar formulário
      setAssunto('')
      setMensagem('')
      setDestinatarioId('')
    }

    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
        <div style={{ 
          padding: '15px', 
          backgroundColor: 'rgba(0, 100, 255, 0.1)', 
          borderRadius: '8px',
          border: '1px solid rgba(0, 255, 0, 0.3)'
        }}>
          <p style={{ color: '#66b3ff', margin: 0, fontSize: '14px', fontWeight: 'bold' }}>
            {safeT?.remetente || 'Remetente'}: {tecnicoNome} ({tecnicoTipo === 'tecnico-interno' ? safeT?.tecnicosInternos : safeT?.tecnicosExternos})
          </p>
        </div>

        <h3 style={{ color: '#66b3ff', marginBottom: '10px' }}>
          {safeT?.novaMensagem || 'Nova Mensagem'}
        </h3>

        {/* Destinatário - Apenas Gestores ou Armazém */}
        <div>
          <label style={{ color: '#ccc', display: 'block', marginBottom: '8px' }}>
            {safeT?.destinatario || 'Destinatário'}:
          </label>
          <div style={{ display: 'flex', gap: '10px', marginBottom: '10px' }}>
            <select
              value={tipoDestinatario}
              onChange={(e) => {
                setTipoDestinatario(e.target.value as 'gestor' | 'armazem')
                setDestinatarioId('')
              }}
              style={{
                padding: '8px',
                backgroundColor: '#222222',
                border: '1px solid rgba(0, 255, 0, 0.3)',
                borderRadius: '4px',
                color: '#fff',
                flex: 1
              }}
            >
              <option value="gestor">{safeT?.gestores || 'Gestores'}</option>
              <option value="armazem">{safeT?.armazem || 'Armazém'}</option>
            </select>
            {tipoDestinatario === 'gestor' && (
              <select
                value={classeDestinatario}
                onChange={(e) => {
                  setClasseDestinatario(e.target.value as any)
                  setDestinatarioId('')
                }}
                style={{
                  padding: '8px',
                  backgroundColor: '#222222',
                  border: '1px solid rgba(0, 255, 0, 0.3)',
                  borderRadius: '4px',
                  color: '#fff',
                  flex: 1
                }}
              >
                <option value="todos-gestores">{safeT?.todosGestores || 'Todos os Gestores'} ({gestores.filter(g => g.area === 'assistencia-tecnica').length})</option>
                <option value="todos-gestores-industrial">{safeT?.todosGestoresIndustrial || 'Todos os Gestores Industrial'} ({gestores.filter(g => g.area === 'industrial').length})</option>
              </select>
            )}
          </div>
          {!classeDestinatario.startsWith('todos-') && tipoDestinatario !== 'armazem' && (
            <select
              value={destinatarioId}
              onChange={(e) => setDestinatarioId(e.target.value)}
              style={{
                padding: '8px',
                backgroundColor: '#222222',
                border: '1px solid rgba(0, 255, 0, 0.3)',
                borderRadius: '4px',
                color: '#fff',
                width: '100%'
              }}
            >
              <option value="">{safeT?.selecionarDestinatario || 'Selecionar Destinatário'}</option>
              {destinatariosDisponiveis.map(d => (
                <option key={d.id} value={d.id}>
                  {d.nome} {d.classe === 'gestor-industrial' ? `(${safeT?.gestoresIndustrial || 'Gestor Industrial'})` : `(${safeT?.gestores || 'Gestor'})`}
                </option>
              ))}
            </select>
          )}
          {tipoDestinatario === 'armazem' && (
            <div style={{ padding: '8px', backgroundColor: '#222222', borderRadius: '4px', color: '#ccc' }}>
              {safeT?.armazem || 'Armazém'}
            </div>
          )}
        </div>

        {/* Assunto */}
        <div>
          <label style={{ color: '#ccc', display: 'block', marginBottom: '8px' }}>
            {safeT?.assunto || 'Assunto'}:
          </label>
          <input
            type="text"
            value={assunto}
            onChange={(e) => setAssunto(e.target.value)}
            placeholder={safeT?.assunto || 'Assunto'}
            style={{
              padding: '10px',
              backgroundColor: '#222222',
              border: '1px solid rgba(0, 255, 0, 0.3)',
              borderRadius: '4px',
              color: '#fff',
              width: '100%'
            }}
          />
        </div>

        {/* Mensagem */}
        <div>
          <label style={{ color: '#ccc', display: 'block', marginBottom: '8px' }}>
            {safeT?.mensagem || 'Mensagem'}:
          </label>
          <textarea
            value={mensagem}
            onChange={(e) => setMensagem(e.target.value)}
            placeholder={safeT?.mensagem || 'Mensagem'}
            rows={8}
            style={{
              padding: '10px',
              backgroundColor: '#222222',
              border: '1px solid rgba(0, 255, 0, 0.3)',
              borderRadius: '4px',
              color: '#fff',
              width: '100%',
              resize: 'vertical'
            }}
          />
        </div>

        {/* Botão Enviar */}
        <button
          onClick={handleEnviar}
          style={{
            padding: '12px 24px',
            backgroundColor: 'rgba(0, 100, 255, 0.3)',
            border: '2px solid #66b3ff',
            borderRadius: '8px',
            color: '#66b3ff',
            fontWeight: 'bold',
            cursor: 'pointer',
            fontSize: '16px',
            transition: 'all 0.3s ease'
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.backgroundColor = 'rgba(0, 100, 255, 0.5)'
            e.currentTarget.style.boxShadow = '0 0 15px rgba(0, 100, 255, 0.5)'
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.backgroundColor = 'rgba(0, 100, 255, 0.3)'
            e.currentTarget.style.boxShadow = 'none'
          }}
        >
          {safeT?.enviar || 'Enviar'}
        </button>
      </div>
    )
  }

  const ComunicacaoMensagensEnviadas = ({
    mensagens,
    safeT
  }: {
    mensagens: MensagemComunicacao[]
    safeT: any
  }) => {
    return (
      <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
        <h3 style={{ color: '#66b3ff', margin: 0 }}>
          {safeT?.mensagensEnviadas || 'Mensagens Enviadas'}
        </h3>

        {mensagens.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '40px', color: '#999' }}>
            <p>{safeT?.nenhumaMensagem || 'Nenhuma mensagem'}</p>
          </div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            {mensagens.map(mensagem => (
              <div
                key={mensagem.id}
                style={{
                  padding: '20px',
                  backgroundColor: '#141414',
                  border: '2px solid rgba(0, 100, 255, 0.2)',
                  borderRadius: '8px'
                }}
              >
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                  <div>
                    <strong style={{ color: '#66b3ff' }}>{mensagem.assunto}</strong>
                    <p style={{ color: '#ccc', fontSize: '12px', margin: '5px 0 0 0' }}>
                      {safeT?.destinatario || 'Para'}: {mensagem.destinatarioNome} ({mensagem.destinatarioTipo})
                    </p>
                  </div>
                  <div style={{ textAlign: 'right', color: '#999', fontSize: '12px' }}>
                    {new Date(mensagem.dataEnvio).toLocaleString('pt-BR')}
                  </div>
                </div>
                <p style={{ color: '#fff', whiteSpace: 'pre-wrap' }}>
                  {mensagem.mensagem}
                </p>
              </div>
            ))}
          </div>
        )}
      </div>
    )
  }

  const BotaoNavegacao = ({ onVoltar, mostrarPaginaInicial = true }: { onVoltar?: () => void, mostrarPaginaInicial?: boolean }) => (
    <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
      {onVoltar && (
        <button 
          className="btn-primary" 
          onClick={onVoltar}
          style={{ 
            padding: '8px 12px', 
            fontSize: '14px',
            display: 'flex',
            alignItems: 'center',
            gap: '6px',
            backgroundColor: '#222222',
            borderColor: '#00ff00'
          }}
          title={safeT?.voltar || 'Voltar'}
        >
          ↶ {safeT?.voltar || 'Voltar'}
        </button>
      )}
      {mostrarPaginaInicial && (
        <button 
          className="btn-primary" 
          onClick={voltarPaginaInicial}
          style={{ 
            padding: '8px 12px', 
            fontSize: '14px',
            display: 'flex',
            alignItems: 'center',
            gap: '6px',
            backgroundColor: '#222222',
            borderColor: 'rgba(0, 255, 0, 0.5)'
          }}
          title={safeT?.paginaInicial || 'Página Inicial'}
        >
          🏠 {safeT?.paginaInicial || 'Página Inicial'}
        </button>
      )}
    </div>
  )

  // Função para voltar à página inicial (fechar todas as abas e modais)
  const voltarPaginaInicial = () => {
    setOpenTabs([])
    setActiveTabId(null)
    // Fechar todos os modais
    setShowModal(false)
    setShowGestoresModal(false)
    setShowEquipamentosModal(false)
    setShowClientesModal(false)
    setShowFornecedoresModal(false)
    setShowRelatorioServicoModal(false)
    setShowRelatorioServicoForm(false)
    setShowPecasSubstituicaoModal(false)
    setShowBibliotecaPecasModal(false)
    setShowAgendaModal(false)
    setShowDesmontadosModal(false)
    setShowCadastroServicosModal(false)
    setShowEquipamentoForm(false)
    setShowGestorForm(false)
    setShowTecnicoForm(false)
    setShowButtonForm(false)
    setShowServicoForm(false)
    setShowRelatoriosModal(false)
    setShowFaturasGeralModal(false)
    setShowPedidoOrcamentoModal(false)
    setSelectedClienteForEquipamento(null)
    setSelectedEquipamentoForRelatorio(null)
    setSelectedFornecedorForFatura(null)
    setViewingRelatorioServico(null)
    setViewingEquipamento(null)
    setEditingRelatorioServico(null)
    setEditingEquipamento(null)
    setEditingGestor(null)
    setEditingTecnico(null)
    setEditingButton(null)
    setEditingServico(null)
    setEditingRelatorio(null)
    setEditingFatura(null)
    setEditingFaturaFornecedor(null)
    setShowEquipamentoClienteForm(false)
    setShowRelatorioForm(false)
    setShowFaturaForm(false)
    setShowFaturaFornecedorForm(false)
  }
  
  const getTabTitle = (type: TabType): string => {
    const t = safeT as any
    const titles: Record<TabType, string> = {
      'gestores': t?.gestoresTitle || 'Gestores e Técnicos',
      'equipamentos': t?.equipamentos || 'CADASTRO DE EQUIPAMENTOS DO ARMAZÉM',
      'familias-grupos': t?.familiasGruposTitle || 'Cadastro de Famílias e Grupos para Checklist',
      'familias-grupos-equipamentos': t?.familiasGruposEquipamentosTitle || 'Cadastro de Famílias e Grupos para os Equipamentos',
      'pre-checklist': t?.preChecklistTitle || 'PRE CHECKLIST',
      'users': t?.userManagement || 'Gestão de Usuários',
      'extras': t?.extras || 'Extras',
      'cadastro-nonato-service': t?.cadastroNonatoServiceTitle || 'CADASTRO DA NONATO SERVICE',
      'ficha-cadastral': t?.fichaCadastralTitle || 'FICHA CADASTRAL DA NONATO SERVICE',
      'clientes': t?.clientes || 'Clientes',
      'fornecedores': t?.fornecedores || 'Fornecedores',
      'relatorio-servico': t?.relatorioServico || 'Relatório de Serviço',
      'pecas-substituicao': t?.pecasSubstituicao || 'Peças de Substituição',
      'biblioteca-pecas': t?.bibliotecaPecas || 'Biblioteca de Peças',
      'importacao-pecas': t?.importacaoPecas || 'Importação de Peças',
      'solicitacao-servico-tecnico': t?.solicitacaoServicoTecnicoTitle || 'SOLICITAÇÃO DE SERVIÇO TÉCNICO',
      'agenda': t?.agenda || 'Agenda',
      'desmontados': t?.desmontados || 'Desmontados',
      'cadastro-servicos': t?.cadastroServicos || 'Cadastro de Serviços',
      'fechamento-relatorios-servicos': t?.fechamentoRelatoriosServicosTitle || 'Fechamento dos Relatórios de Serviços',
      'translator': t?.translator || 'Tradutor de Idiomas',
      'administrador': t?.administrador || 'Administrador',
      'estado-visual-tecnico': t?.estadoVisualTecnico || 'Estado Visual do Técnico',
      'informacoes-conhecimento-tecnicos': t?.informacoesConhecimentoTecnicosTitle || 'Informações de Conhecimento dos Técnicos',
      'gestao-custos': t?.gestaoCustosTitle || 'Gestão de Custos',
      'biblioteca-relatorios': t?.bibliotecaRelatoriosTitle || 'Biblioteca de Relatórios Salvos',
      'relatorios-excluidos-clientes': (t as any)?.relatoriosExcluidosClientesTitle || 'Relatórios Excluídos / Clientes',
      'gestao-financeira': t?.gestaoFinanceiraTitle || 'Gestão Financeira',
      'clientes-financeiro': t?.clientesFinanceiroTitle || 'Clientes / Financeiro',
      'orcamentos-avulso': t?.orcamentosAvulsoTitle || 'Orçamentos Avulso',
      'pedido-orcamentos-avulso': t?.pedidoOrcamentosAvulsoTitle || 'PEDIDO DE ORÇAMENTOS AVULSO',
      'registro-despesas': t?.registroDespesasTitle || 'Registro de Despesas',
      'comprovantes-despesas': t?.comprovantesDespesasTitle || 'COMPROVANTES DE DESPESAS',
      'mapa-visual-separacao-pecas': t?.mapaVisualSeparacaoPecasTitle || 'Mapa Visual de Separação de Peças / Cliente',
      'manuais-informacoes-tecnicas': t?.manuaisInformacoesTecnicasTitle || 'Manuais e Informações Técnica dos Equipamentos',
      'almoxarifado-armazem': t?.almoxarifadoArmazemTitle || 'Almoxarifado / Armazém',
      'checklist': t?.checklistTitle || 'CHECKLIST',
      'checklist-hub': t?.checklistGroupTitle || 'GESTÃO DOS CHECKLIST',
      'gestao-grupos-checklist': t?.gestaoGruposChecklistTitle || 'GESTÃO DOS GRUPOS PARA CHECKLIST (CHECKLIST FINAL PARA A ENTREGA)',
      'ordem-preparacao': t?.ordemPreparacaoTitle || 'ORDEM DE PREPARAÇÃO',
      'formularios-checklist-tecnicos': t?.formulariosChecklistTecnicosTitle || 'FORMULARIOS E CHECKLIST P/ TECNICOS',
      'verificacao-final-entrega': t?.verificacaoFinalEntregaTitle || 'VERIFICAÇÃO FINAL ANTES DA ENTREGA DO EQUIPAMENTO P/ O CLIENTE',
      'comunicacao-interna': t?.comunicacaoInternaTitle || 'COMUNICAÇÃO INTERNA C/ GESTORES E TECNICOS',
      'hub-comunicacao': t?.hubComunicacao || 'HUB DE COMUNICAÇÃO',
      'mensagens-internas': t?.mensagensInternas || 'MENSAGENS INTERNAS / GESTORES',
      'mensagens-internas-tecnicos': t?.mensagensInternasTecnicos || 'MENSAGENS INTERNAS / TÉCNICOS',
      'tecnicos-internos': t?.tecnicosInternos || 'TÉCNICOS INTERNOS',
      'tecnicos-externos': t?.tecnicosExternos || 'TÉCNICOS EXTERNOS',
      'alerta-mensagens': t?.alertaMensagens || 'ALERTA DE MENSAGENS',
      'protocolos-servico': (t as any)?.protocolosServicoTitle || 'Protocolos de Serviço',
      'manual-programa': (t as any)?.manualProgramaTitle || 'Manual do Programa'
    }
    return titles[type] || type
  }

  // Chave de tradução para o Help da seção (ex: equipamentos -> helpEquipamentos)
  const getHelpKey = (type: TabType): string => {
    const key = 'help' + type.split('-').map(s => s.charAt(0).toUpperCase() + s.slice(1)).join('')
    return key
  }
  const getHelpContent = (type: TabType): string => {
    const t = safeT as Record<string, string | undefined>
    const key = getHelpKey(type)
    const text = t?.[key]
    return text || (t?.helpDefault || 'Consulte o manual do sistema para mais informações sobre esta secção.')
  }
  // Evita abrir modais automaticamente na carga inicial (ex: HMR/estado preservado)
  const [tabsOpenedByUser, setTabsOpenedByUser] = useState(false)
  
  // Estados para Agenda
  const [agendamentos, setAgendamentos] = useState<Agendamento[]>([])
  const [showAgendaModal, setShowAgendaModal] = useState(false)
  const [showAgendaForm, setShowAgendaForm] = useState(false)
  const [editingAgendamento, setEditingAgendamento] = useState<Agendamento | null>(null)
  const [agendaForm, setAgendaForm] = useState<Agendamento>({
    id: '',
    tipo: 'pre-agendamento',
    tecnico: '',
    cliente: '',
    clienteId: '',
    equipamento: '',
    equipamentoId: '',
    data: new Date().toISOString().split('T')[0],
    hora: '09:00',
    duracaoEstimada: '2',
    tipoServico: '',
    observacoesTecnicas: '',
    necessidadePecas: false,
    codigoNotaFiscal: '',
    pecasAnexadas: [],
    status: 'pendente',
    telefone: '',
    endereco: '',
    cidade: '',
    dataCriacao: new Date().toISOString()
  })
  const [filtroAgenda, setFiltroAgenda] = useState<'todos' | 'pre-agendamento' | 'agendamento-tecnico' | 'nenhum' | 'folga' | 'doente' | 'ferias'>('todos')
  const [filtroTecnicoAgenda, setFiltroTecnicoAgenda] = useState('')
  const [filtroDataAgenda, setFiltroDataAgenda] = useState('')
  const [visualizacaoAgenda, setVisualizacaoAgenda] = useState<'lista' | 'calendario'>('lista')
  const [calendarioMes, setCalendarioMes] = useState(new Date().getMonth())
  const [calendarioAno, setCalendarioAno] = useState(new Date().getFullYear())
  const [tecnicoSelecionadoCalendario, setTecnicoSelecionadoCalendario] = useState<string | null>(null)
  const [tecnicoCalendarioAtivo, setTecnicoCalendarioAtivo] = useState<string>('') // técnico selecionado para o modo calendário
  const [datasSelecionadasCalendario, setDatasSelecionadasCalendario] = useState<string[]>([])
  const [statusDiaSelecionado, setStatusDiaSelecionado] = useState<'nenhum' | 'folga' | 'doente' | 'ferias'>('nenhum')
  const [statusTecnicoPorDia, setStatusTecnicoPorDia] = useState<Record<string, Record<string, 'nenhum' | 'pre' | 'agendamento' | 'folga' | 'doente' | 'ferias'>>>({})
  const [execucaoTecnicoPorDia, setExecucaoTecnicoPorDia] = useState<Record<string, Record<string, 'pendente' | 'concluido'>>>({})
  const [modoExecucaoResumo, setModoExecucaoResumo] = useState<'pendente' | 'concluido'>('pendente')
  const [showSelecionarPecasModal, setShowSelecionarPecasModal] = useState(false)
