  // Sistema de Tradutor - languageCodes precisa estar definido antes de handleQuickTranslate
  const languageCodes: { [key: string]: string } = {
    'pt-BR': 'pt',
    'es': 'es',
    'fr': 'fr',
    'it': 'it',
    'de': 'de',
    'en': 'en'
  }

  const handleQuickTranslate = async (text: string, fromLang?: string, toLang?: string) => {
    const from = fromLang || selectedLanguage
    const to = toLang || (selectedLanguage === 'pt-BR' ? 'en' : 'pt-BR') // Traduzir para português ou inglês por padrão
    
    if (from === to) {
      setQuickTranslateResult(text)
      return
    }

    const textNorm = text.trim().toLowerCase()
    const fromLibrary = translatorLibrary.find(
      e => e.sourceLang === from && e.targetLang === to && e.sourceText.trim().toLowerCase() === textNorm
    )
    if (fromLibrary) {
      setQuickTranslateResult(fromLibrary.targetText)
      return
    }

    setQuickTranslating(true)
    setQuickTranslateResult('')

    try {
      const fromCode = languageCodes[from] || from
      const toCode = languageCodes[to] || to
      
      // Usar apenas API MyMemory (sem problemas de CORS)
      const response = await fetch(
        `https://api.mymemory.translated.net/get?q=${encodeURIComponent(text)}&langpair=${fromCode}|${toCode}`,
        { 
          method: 'GET',
          headers: { 'Accept': 'application/json' }
        }
      )

      if (response.ok) {
        const data = await response.json()
        if (data.responseData && data.responseData.translatedText) {
          setQuickTranslateResult(data.responseData.translatedText)
          setQuickTranslating(false)
          return
        }
      }

      // Se falhar, mostrar mensagem de erro
      const tTyped = t as any
      setQuickTranslateResult(tTyped.translationError || 'Erro ao traduzir. Verifique sua conexão e tente novamente.')
    } catch (error) {
      // Silenciar erros de rede para não poluir o console
      const tTyped = t as any
      setQuickTranslateResult(tTyped.translationError || 'Erro ao traduzir. Verifique sua conexão e tente novamente.')
    }

    setQuickTranslating(false)
  }

