  // Função para obter o nome traduzido do botão
  const getButtonName = useCallback((button: SidebarButton) => {
    // IDs dos botões da gestão técnica que SEMPRE devem ser traduzidos (ignorar customName)
    const gestaoTecnicaButtonIds = [
      'gestores-default',
      'clientes-default', 
      'fornecedores-default',
      'relatorio-servico-default',
      'biblioteca-pecas-default',
      'solicitacao-servico-tecnico-default',
      'agenda-default',
      'cadastro-servicos-default',
      'fechamento-relatorios-servicos-default',
      'orcamentos-avulso-default',
      'pedido-orcamentos-avulso-default',
      'registro-despesas-default',
      'mapa-visual-separacao-pecas-default'
    ]
    
    const isGestaoTecnicaButton = gestaoTecnicaButtonIds.includes(button.id || '')
    
    // PRIORIDADE 1: Se é botão da gestão técnica, SEMPRE traduzir (ignorar customName completamente)
    if (isGestaoTecnicaButton) {
      // Primeiro tenta usar translationKey se existir
      if (button.translationKey) {
        const translatedName = (safeT as any)[button.translationKey]
        if (translatedName) {
          return translatedName
        }
      }
      // Fallback direto por ID para garantir tradução
      if (button.id === 'gestores-default') {
        return safeT?.gestoresTitle || button.name || ''
      } else if (button.id === 'clientes-default') {
        return safeT?.clientesTitle || button.name || ''
      } else if (button.id === 'fornecedores-default') {
        return safeT?.fornecedoresTitle || button.name || ''
      } else if (button.id === 'relatorio-servico-default') {
        return safeT?.relatorioServicoTitle || button.name || ''
      } else if (button.id === 'biblioteca-pecas-default') {
        return safeT?.cadastroPecasBibliotecaTitle || button.name || ''
      } else if (button.id === 'solicitacao-servico-tecnico-default') {
        return safeT?.solicitacaoServicoTecnicoTitle || button.name || ''
      } else if (button.id === 'agenda-default') {
        return safeT?.agendaTitle || button.name || ''
      } else if (button.id === 'estado-visual-tecnico-default') {
        return (safeT?.estadoVisualTecnico || button.name || '').toUpperCase()
      } else if (button.id === 'cadastro-servicos-default') {
        return safeT?.cadastroServicosTitle || button.name || ''
      } else if (button.id === 'fechamento-relatorios-servicos-default') {
        return (safeT as any)?.fechamentoRelatoriosServicosTitle || button.name || ''
      } else if (button.id === 'orcamentos-avulso-default') {
        return safeT?.orcamentosAvulsoTitle || button.name || ''
      } else if (button.id === 'registro-despesas-default') {
        return safeT?.registroDespesasTitle || button.name || ''
      } else if (button.id === 'comprovantes-despesas-default') {
        return safeT?.comprovantesDespesasTitle || button.name || ''
      } else if (button.id === 'mapa-visual-separacao-pecas-default') {
        return safeT?.mapaVisualSeparacaoPecasTitle || button.name || ''
      } else if (button.id === 'almoxarifado-armazem-default') {
        return safeT?.almoxarifadoArmazemTitle || button.name || ''
      }
    }
    
    // PRIORIDADE 2: Se tem translationKey, SEMPRE usar a tradução do idioma atual (mesmo que tenha nome salvo)
    if (button.translationKey) {
      const translatedName = (safeT as any)[button.translationKey]
      if (translatedName) {
        // Se for o botão de estado visual do técnico, retornar em maiúsculas
        if (button.id === 'estado-visual-tecnico-default') {
          return String(translatedName).toUpperCase()
        }
        return translatedName
      }
    }
    
    // PRIORIDADE 3: Se o nome foi explicitamente customizado pelo usuário (customName === true), usar esse nome (não muda com idioma)
    // MAS apenas se NÃO for botão da gestão técnica
    if (button.customName === true && button.name && !isGestaoTecnicaButton) {
      return button.name
    }
    
    // PRIORIDADE 4: Fallback para botões padrão conhecidos por ID
    if (button.id === 'extras-default' || button.id === 'administrador-default') {
      return safeT?.extras || safeT?.administrador || button.name || ''
    } else if (button.id === 'cadastro-nonato-service-default') {
      return safeT?.cadastroNonatoServiceTitle || button.name || 'CADASTRO DA NONATO SERVICE'
    } else if (button.id === 'gestao-financeira-default') {
      return safeT?.gestaoFinanceiraTitle || button.name || ''
      } else if (button.id === 'familias-grupos-default') {
        return safeT?.familiasGruposTitle || button.name || ''
      } else if (button.id === 'familias-grupos-equipamentos-default') {
        return safeT?.familiasGruposEquipamentosTitle || button.name || ''
      } else if (button.id === 'equipamentos-default') {
        return safeT?.equipamentosTitle || button.name || ''
      } else if (button.id === 'checklist-group-default') {
        return safeT?.checklistGroupTitle || button.name || ''
      } else if (button.id === 'pre-checklist-default') {
        return safeT?.preChecklistSubTitle || safeT?.preChecklistTitle || button.name || ''
      } else if (button.id === 'checklist-default') {
        return safeT?.checklistSubTitle || safeT?.checklistTitle || button.name || ''
      } else if (button.id === 'comunicacao-interna-default') {
        return safeT?.comunicacaoInternaTitle || button.name || ''
      } else if (button.id === 'mensagens-internas-default') {
        return safeT?.mensagensInternas || button.name || ''
      } else if (button.id === 'mensagens-internas-tecnicos-default') {
        return safeT?.mensagensInternasTecnicos || button.name || ''
      } else if (button.id === 'alerta-mensagens-default') {
        return safeT?.alertaMensagens || button.name || ''
    } else if (button.id === 'desmontados-default') {
      return safeT?.desmontadosTitle || button.name || ''
    } else     if (button.id === 'gestao-tecnica-default') {
      return safeT?.gestaoTecnicaTitle || button.name || ''
    } else if (button.id === 'gestao-custos-default') {
      return safeT?.gestaoCustosTitle || button.name || ''
    } else if (button.id === 'gestao-industrial-default') {
      return safeT?.gestaoIndustrialTitle || button.name || ''
    }
    
    // PRIORIDADE 5: Usar o nome salvo como último recurso
    return button.name || ''
  }, [safeT])

  const handleSaveButton = () => {
    if (!buttonForm.name || !buttonForm.action) {
      alert(t.fillAllFields)
      return
    }

    // Verificar se o nome corresponde a alguma tradução conhecida
    const findTranslationKey = (name: string): string | undefined => {
      const nameLower = name.toLowerCase().trim()
      const translationKeys = Object.keys(translations['pt-BR']) as Array<keyof typeof translations['pt-BR']>
      
      for (const key of translationKeys) {
        const ptValue = String(translations['pt-BR'][key]).toLowerCase().trim()
        if (ptValue === nameLower) {
          return key as string
        }
      }
      return undefined
    }

    // Verificar se o nome corresponde a uma tradução conhecida
    const translationKey = findTranslationKey(buttonForm.name)
    const defaultTranslation = translationKey ? (translations['pt-BR'] as any)[translationKey] : null
    
    // Se o nome editado é diferente da tradução padrão, marcar como customizado
    // Isso permite que o nome customizado seja preservado mesmo ao mudar de idioma
    const isCustomName = !translationKey || !defaultTranslation || buttonForm.name !== defaultTranslation

    if (editingButton) {
      const updatedButtons = sidebarButtons.map(b => 
        b.id === editingButton.id 
          ? { 
              ...b, 
              name: buttonForm.name, 
              action: buttonForm.action, 
              translationKey: translationKey || b.translationKey, // Manter translationKey se existir
              customName: isCustomName // Marcar se é nome customizado
            }
          : b
      )
      setSidebarButtons(updatedButtons)
      saveData('nonato-sidebar-buttons', updatedButtons)
    } else {
      const newButton: SidebarButton = {
        id: Date.now().toString(),
        name: buttonForm.name,
        action: buttonForm.action,
        order: sidebarButtons.length,
        translationKey: translationKey,
        customName: isCustomName
      }
      const updatedButtons = [...sidebarButtons, newButton]
      setSidebarButtons(updatedButtons)
      saveData('nonato-sidebar-buttons', updatedButtons)
    }

    setShowButtonForm(false)
    setButtonForm({ name: '', action: '' })
    setEditingButton(null)
  }

  const handleMoveButton = (buttonId: string, direction: 'up' | 'down') => {
    const index = sidebarButtons.findIndex(b => b.id === buttonId)
    if (index === -1) return

    const newIndex = direction === 'up' ? index - 1 : index + 1
    if (newIndex < 0 || newIndex >= sidebarButtons.length) return

    const updatedButtons = [...sidebarButtons]
    const [moved] = updatedButtons.splice(index, 1)
    updatedButtons.splice(newIndex, 0, moved)
    
    const reordered = updatedButtons.map((btn, idx) => ({ ...btn, order: idx }))
    setSidebarButtons(reordered)
    saveData('nonato-sidebar-buttons', reordered)
  }

  const handleDragStart = (buttonId: string) => {
    setDraggedButton(buttonId)
  }

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault()
    setDragOverIndex(index)
  }

  const handleDragLeave = () => {
    setDragOverIndex(null)
  }

  const handleDrop = (e: React.DragEvent, dropIndex: number) => {
    e.preventDefault()
    if (!draggedButton) return

    // Ordenar botões por ordem atual antes de calcular índices
    const sortedButtons = [...sidebarButtons].sort((a, b) => a.order - b.order)
    const dragIndex = sortedButtons.findIndex(b => b.id === draggedButton)
    
    if (dragIndex === -1 || dragIndex === dropIndex) {
      setDraggedButton(null)
      setDragOverIndex(null)
      return
    }

    // Reordenar baseado nos índices corretos
    const updatedButtons = [...sortedButtons]
    const [moved] = updatedButtons.splice(dragIndex, 1)
    updatedButtons.splice(dropIndex, 0, moved)
    
    // Atualizar a propriedade order de todos os botões
    const reordered = updatedButtons.map((btn, idx) => ({ ...btn, order: idx }))
    setSidebarButtons(reordered)
    
    // Salvar
    if (typeof window !== 'undefined') {
      try { localStorage.setItem('nonato-sidebar-buttons', JSON.stringify(reordered)) } catch (e) {}
    }
    saveData('nonato-sidebar-buttons', reordered).catch(() => {})
    
    setDraggedButton(null)
    setDragOverIndex(null)
  }

  // Ao soltar: se for em grupo diferente, move o botão; se for no mesmo grupo, reordena
  const handleDropWithGroup = (e: React.DragEvent, dropIndex: number, targetGroup: 'gestao-tecnica' | 'gestao-custos' | 'gestao-industrial' | 'gestao-financeira' | 'checklist-group' | 'comunicacao-interna' | 'manuais-informacoes-tecnicas' | 'almoxarifado-armazem' | 'outros') => {
    e.preventDefault()
    if (!draggedButton) return
    const draggedBtn = sidebarButtons.find(b => b.id === draggedButton)
    const isSameGroup = draggedBtn && (draggedBtn.group || 'outros') === targetGroup
    if (isSameGroup) {
      handleDrop(e, dropIndex)
    } else {
      handleMoveButtonToGroup(draggedButton, targetGroup)
      setDraggedButton(null)
      setDragOverIndex(null)
    }
  }

