  const handleDeleteTipoGestor = (tipoId: string) => {
    // Verificar se há gestores usando este tipo
    const gestoresUsandoTipo = gestores.filter(g => g.area === tipoId)
    if (gestoresUsandoTipo.length > 0) {
      alert(`Não é possível excluir este tipo. Existem ${gestoresUsandoTipo.length} gestor(es) usando este tipo. Primeiro altere a área desses gestores.`)
      return
    }

    if (window.confirm('Tem certeza que deseja excluir este tipo de gestor?')) {
      const updatedTipos = tiposGestores.filter(t => t.id !== tipoId)
      setTiposGestores(updatedTipos)
      saveData('nonato-tipos-gestores', updatedTipos)
    }
  }

  const handleSaveTipoGestor = () => {
    if (!tipoGestorForm.nome || !tipoGestorForm.id) {
      alert('Preencha o nome e o ID do tipo')
      return
    }

    // Gerar ID se não existir
    if (!editingTipoGestor && !tipoGestorForm.id) {
      tipoGestorForm.id = tipoGestorForm.nome.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '')
    }

    // Verificar se ID já existe (exceto se estiver editando)
    if (!editingTipoGestor && tiposGestores.some(t => t.id === tipoGestorForm.id)) {
      alert('Já existe um tipo com este ID. Escolha outro nome.')
      return
    }

    let updatedTipos: TipoGestor[]
    if (editingTipoGestor) {
      // Atualizar tipo existente
      updatedTipos = tiposGestores.map(t => 
        t.id === editingTipoGestor.id ? tipoGestorForm : t
      )
      // Se o ID mudou, atualizar todos os gestores que usam esse tipo
      if (editingTipoGestor.id !== tipoGestorForm.id) {
        const updatedGestores = gestores.map(g => 
          g.area === editingTipoGestor.id ? { ...g, area: tipoGestorForm.id } : g
        )
        setGestores(updatedGestores)
        saveData('nonato-gestores', updatedGestores)
      }
    } else {
      // Adicionar novo tipo
      updatedTipos = [...tiposGestores, tipoGestorForm]
    }

    setTiposGestores(updatedTipos)
    saveData('nonato-tipos-gestores', updatedTipos)
    setShowGerenciarTiposGestores(false)
    setEditingTipoGestor(null)
    setTipoGestorForm({ id: '', nome: '', cor: '#00ff00', icone: '👤', ordem: 0 })
  }

  // Função auxiliar para obter informações do tipo de gestor
  const getTipoGestorInfo = (areaId: string) => {
    return tiposGestores.find(t => t.id === areaId) || null
  }

  const handleAddTecnico = () => {
    setEditingTecnico(null)
    // Se estiver na aba de técnicos internos, definir como interno por padrão
    // Se estiver na aba de técnicos externos, definir como externo por padrão
    const tipoPadrao = tecnicosTipoTab === 'externo' ? 'external' : 'internal'
    setTecnicoForm({ name: '', email: '', phone: '', address: '', type: tipoPadrao, photo: '' })
    setShowTecnicoForm(true)
  }

  const handleEditTecnico = (tecnico: Tecnico) => {
    setEditingTecnico(tecnico)
    setTecnicoForm({ 
      name: tecnico.name, 
      email: tecnico.email, 
      phone: tecnico.phone, 
      address: tecnico.address, 
      type: tecnico.type,
      photo: tecnico.photo || ''
    })
    setShowTecnicoForm(true)
  }

  const handleDeleteTecnico = (tecnicoId: string) => {
    if (window.confirm(t.confirmDeleteTecnico)) {
      const updatedTecnicos = tecnicos.filter(t => t.id !== tecnicoId)
      setTecnicos(updatedTecnicos)
      saveData('nonato-tecnicos', updatedTecnicos)
    }
  }

  const handleTecnicoPhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file || !file.type.startsWith('image/')) {
      alert(t.selectImage)
      return
    }

    const reader = new FileReader()
    reader.onload = (event) => {
      const result = event.target?.result as string
      setTecnicoForm({ ...tecnicoForm, photo: result })
    }
    reader.readAsDataURL(file)
  }

  const handleRemoveTecnicoPhoto = () => {
    setTecnicoForm({ ...tecnicoForm, photo: '' })
  }

  const handleSaveTecnico = () => {
    if (!tecnicoForm.name || !tecnicoForm.email || !tecnicoForm.phone) {
      alert(t.fillAllFields)
      return
    }

    if (editingTecnico) {
      const updatedTecnicos = tecnicos.map(t => 
        t.id === editingTecnico.id 
          ? { ...t, ...tecnicoForm }
          : t
      )
      setTecnicos(updatedTecnicos)
      saveData('nonato-tecnicos', updatedTecnicos)
    } else {
      const newTecnico: Tecnico = {
        id: Date.now().toString(),
        ...tecnicoForm
      }
      const updatedTecnicos = [...tecnicos, newTecnico]
      setTecnicos(updatedTecnicos)
      saveData('nonato-tecnicos', updatedTecnicos)
      
      // Abrir automaticamente a comunicação para o novo técnico
      // Verificar se a aba de comunicação está aberta
      const comunicacaoTab = openTabs.find(tab => tab.type === 'comunicacao-interna')
      if (!comunicacaoTab) {
        // Se não estiver aberta, abrir
        openTab('comunicacao-interna', getTabTitle('comunicacao-interna'))
      }
      // Selecionar o técnico recém-criado
      setTimeout(() => {
        setTecnicoSelecionado(newTecnico.id)
        setComunicacaoTecnicoActiveTab('enviar')
      }, 100)
    }

    setShowTecnicoForm(false)
    setTecnicoForm({ name: '', email: '', phone: '', address: '', type: 'internal', photo: '' })
    setEditingTecnico(null)
  }

  // Função para criar backup completo
  const handleCreateBackup = async () => {
    try {
      // Coletar TODOS os dados do localStorage
      const backupData = {
        version: '1.0.0',
        date: new Date().toISOString(),
        data: {
          logo: localStorage.getItem('nonato-logo'),
          logoType: localStorage.getItem('nonato-logo-type'),
          language: localStorage.getItem('nonato-language'),
          users: localStorage.getItem('nonato-users'),
          gestores: localStorage.getItem('nonato-gestores'),
          tecnicos: localStorage.getItem('nonato-tecnicos'),
          conhecimentoTecnicos: localStorage.getItem('nonato-conhecimento-tecnicos'),
          equipamentos: localStorage.getItem('nonato-equipamentos'),
          clientes: localStorage.getItem('nonato-clientes'),
          clientePrioritario: localStorage.getItem('nonato-cliente-prioritario'),
          fornecedores: localStorage.getItem('nonato-fornecedores'),
          sidebarButtons: localStorage.getItem('nonato-sidebar-buttons')
        }
      }

      const jsonStr = JSON.stringify(backupData, null, 2)
      const dateStr = new Date().toISOString().split('T')[0]
      const fileName = `${(t as any).backupFileName || 'backup'}-${dateStr}.json`

      if (backupMethod === 'server' && backupServerUrl.trim()) {
        const url = backupServerUrl.trim()
        
        // Verificar se é uma URL HTTP/HTTPS ou um caminho de arquivo
        if (url.startsWith('http://') || url.startsWith('https://')) {
          // Enviar para servidor via HTTP
          try {
            const response = await fetch(url, {
              method: 'POST',
              headers: {
                'Content-Type': 'application/json',
              },
              body: jsonStr
            })

            if (response.ok) {
              alert(t.backupSendSuccess)
            } else {
              const errorText = await response.text()
              throw new Error(`Erro HTTP ${response.status}: ${errorText}`)
            }
          } catch (error) {
            alert(((t as any).backupSendError || 'Erro ao enviar backup') + ': ' + (error as Error).message)
            return
          }
        } else {
          // Tentar usar File System Access API para salvar em diretório específico
          try {
            // @ts-ignore - File System Access API pode não estar disponível em todos os navegadores
            if ('showSaveFilePicker' in window) {
              // @ts-ignore
              const fileHandle = await window.showSaveFilePicker({
                suggestedName: fileName,
                types: [{
                  description: 'Arquivo JSON',
                  accept: { 'application/json': ['.json'] }
                }]
              })
              
              // @ts-ignore
              const writable = await fileHandle.createWritable()
              await writable.write(jsonStr)
              await writable.close()
              
              alert(((t as any).backupSuccess || 'Backup realizado com sucesso!') + '\n' + 'Backup salvo em: ' + fileHandle.name)
            } else {
              // Fallback: download normal
              const blob = new Blob([jsonStr], { type: 'application/json' })
              const blobUrl = URL.createObjectURL(blob)
              const link = document.createElement('a')
              link.href = blobUrl
              link.download = fileName
              document.body.appendChild(link)
              link.click()
              document.body.removeChild(link)
              URL.revokeObjectURL(blobUrl)
              alert(((t as any).backupSuccess || 'Backup realizado com sucesso!') + '\n' + ((t as any).backupDownloaded || 'Backup baixado'))
            }
          } catch (error: any) {
            // Se o usuário cancelar, não mostrar erro
            if (error.name !== 'AbortError') {
              alert(t.errorSavingBackup + ': ' + error.message)
            }
            return
          }
        }
      } else {
        // Download local padrão
        const blob = new Blob([jsonStr], { type: 'application/json' })
        const url = URL.createObjectURL(blob)
        
        // Criar link de download
        const link = document.createElement('a')
        link.href = url
        link.download = fileName
        document.body.appendChild(link)
        link.click()
        document.body.removeChild(link)
        URL.revokeObjectURL(url)

        alert(((t as any).backupSuccess || 'Backup realizado com sucesso!') + '\n' + ((t as any).backupDownloaded || 'Backup baixado'))
      }
    } catch (error) {
      alert(t.errorCreatingBackup + ': ' + (error as Error).message)
    }
  }

  // Função para criar backup automático (salva no localStorage)
  const createAutoBackup = useCallback(() => {
    try {
      const AUTO_BACKUP_STORAGE_KEY = 'nonato-auto-backups'
      const MAX_AUTO_BACKUPS = 3
      // Segurança: evita estourar quota com blobs gigantes (ex.: base64 de imagens)
      const MAX_VALUE_CHARS = 200_000

      const isProbablyBase64Image = (value: string) =>
        value.startsWith('data:image/') || value.startsWith('data:video/')

      const safeGet = (key: string) => {
        const v = localStorage.getItem(key)
        if (v === null) return null
        if (v.length > MAX_VALUE_CHARS) return null
        if (isProbablyBase64Image(v)) return null
        return v
      }

      const stripPhotoFieldFromJson = (json: string | null) => {
        if (!json) return null
        // Se vier como base64 gigante, já foi bloqueado pelo safeGet — aqui é só “higiene”
        try {
          const parsed = JSON.parse(json)
          if (Array.isArray(parsed)) {
            return JSON.stringify(
              parsed.map((item) => {
                if (item && typeof item === 'object' && 'photo' in item) {
                  const { photo, ...rest } = item as any
                  return rest
                }
                return item
              })
            )
          }
          if (parsed && typeof parsed === 'object' && 'photo' in parsed) {
            const { photo, ...rest } = parsed as any
            return JSON.stringify(rest)
          }
          return json
        } catch {
          return json
        }
      }

      const tryPersistAutoBackups = (backups: Array<{ timestamp: number; data: any }>) => {
        // Tenta salvar; se estourar quota, remove os mais antigos até caber.
        let working = backups.slice()
        while (working.length > 0) {
          try {
            localStorage.setItem(AUTO_BACKUP_STORAGE_KEY, JSON.stringify(working))
            return { ok: true, kept: working.length }
          } catch (e: any) {
            // Apenas para quota: remove 1 backup antigo e tenta de novo
            const msg = String(e?.message || e)
            if (e?.name === 'QuotaExceededError' || msg.toLowerCase().includes('quota')) {
              working = working.slice(0, Math.max(0, working.length - 1))
              continue
            }
            throw e
          }
        }
        // Se nem 1 backup couber, remove o storage de backups automáticos
        try {
          localStorage.removeItem(AUTO_BACKUP_STORAGE_KEY)
        } catch {}
        return { ok: false, kept: 0 }
      }

      // Coletar dados do localStorage (com proteção contra itens gigantes)
      const backupData = {
        version: '1.0.0',
        date: new Date().toISOString(),
        timestamp: Date.now(),
        data: {
          // Logo pode ser base64 e explodir a quota. Guardar apenas se couber.
          logo: safeGet('nonato-logo'),
          logoType: localStorage.getItem('nonato-logo-type'),
          language: localStorage.getItem('nonato-language'),
          users: safeGet('nonato-users'),
          // Gestores/Técnicos podem conter "photo" base64 — remove antes de salvar
          gestores: stripPhotoFieldFromJson(safeGet('nonato-gestores')),
          tecnicos: stripPhotoFieldFromJson(safeGet('nonato-tecnicos')),
          conhecimentoTecnicos: safeGet('nonato-conhecimento-tecnicos'),
          equipamentos: safeGet('nonato-equipamentos'),
          clientes: safeGet('nonato-clientes'),
          clientePrioritario: safeGet('nonato-cliente-prioritario'),
          fornecedores: safeGet('nonato-fornecedores'),
          relatoriosServico: safeGet('nonato-relatorios-servico'),
          pecasBiblioteca: safeGet('nonato-pecas-biblioteca'),
          categoriasPecas: safeGet('nonato-categorias-pecas'),
          subcategoriasPecas: safeGet('nonato-subcategorias-pecas'),
          agendamentos: safeGet('nonato-agendamentos'),
          sidebarButtons: safeGet('nonato-sidebar-buttons')
        }
      }

      // Obter backups existentes
      const existingBackupsStr = localStorage.getItem(AUTO_BACKUP_STORAGE_KEY)
      let backups: Array<{ timestamp: number; data: any }> = []
      
      if (existingBackupsStr) {
        try {
          backups = JSON.parse(existingBackupsStr)
        } catch (e) {
          backups = []
        }
      }

      // Adicionar novo backup
      backups.push({
        timestamp: backupData.timestamp,
        data: backupData
      })

      // Ordenar por timestamp (mais recente primeiro)
      backups.sort((a, b) => b.timestamp - a.timestamp)

      // Manter apenas os mais recentes (reduz pressão de quota)
      if (backups.length > MAX_AUTO_BACKUPS) {
        backups = backups.slice(0, MAX_AUTO_BACKUPS)
      }

      // Salvar backups no localStorage com fallback de quota
      const persisted = tryPersistAutoBackups(backups)

      if (!persisted.ok) {
        console.warn('⚠️ Backup automático não pôde ser salvo por falta de espaço (quota).')
      }
      
      return persisted.ok
    } catch (error) {
      console.error('Erro ao criar backup automático:', error)
      return false
    }
  }, [])

  // Função para restaurar backup automático
  const restoreAutoBackup = (backup: { timestamp: number; data: any }) => {
    try {
      if (!backup || !backup.data || !backup.data.data) {
        alert(t.invalidBackup || 'Backup inválido')
        return false
      }

      const backupData = backup.data.data

      // Restaurar todos os dados
      if (backupData.logo !== null) localStorage.setItem('nonato-logo', backupData.logo)
      if (backupData.logoType !== null) localStorage.setItem('nonato-logo-type', backupData.logoType)
      if (backupData.language !== null) localStorage.setItem('nonato-language', backupData.language)
      if (backupData.users !== null) localStorage.setItem('nonato-users', backupData.users)
      if (backupData.gestores !== null) localStorage.setItem('nonato-gestores', backupData.gestores)
      if (backupData.tecnicos !== null) localStorage.setItem('nonato-tecnicos', backupData.tecnicos)
      if (backupData.conhecimentoTecnicos !== null) localStorage.setItem('nonato-conhecimento-tecnicos', backupData.conhecimentoTecnicos)
      if (backupData.equipamentos !== null) localStorage.setItem('nonato-equipamentos', backupData.equipamentos)
      if (backupData.clientes !== null) localStorage.setItem('nonato-clientes', backupData.clientes)
      if (backupData.clientePrioritario !== null) localStorage.setItem('nonato-cliente-prioritario', backupData.clientePrioritario)
      if (backupData.fornecedores !== null) localStorage.setItem('nonato-fornecedores', backupData.fornecedores)
      if (backupData.relatoriosServico !== null) localStorage.setItem('nonato-relatorios-servico', backupData.relatoriosServico)
      if (backupData.pecasBiblioteca !== null) localStorage.setItem('nonato-pecas-biblioteca', backupData.pecasBiblioteca)
      if (backupData.categoriasPecas !== null) localStorage.setItem('nonato-categorias-pecas', backupData.categoriasPecas)
      if (backupData.subcategoriasPecas !== null) localStorage.setItem('nonato-subcategorias-pecas', backupData.subcategoriasPecas)
      if (backupData.agendamentos !== null) localStorage.setItem('nonato-agendamentos', backupData.agendamentos)
      if (backupData.sidebarButtons !== null) localStorage.setItem('nonato-sidebar-buttons', backupData.sidebarButtons)

      alert(t.backupRestoredSuccess || 'Backup restaurado com sucesso! A página será recarregada.')
      window.location.reload()
      return true
    } catch (error) {
      alert(t.errorRestoringBackup + ': ' + (error as Error).message)
      return false
    }
  }

  // Função para obter lista de backups automáticos
  const getAutoBackups = () => {
    try {
      const backupsStr = localStorage.getItem('nonato-auto-backups')
      if (!backupsStr) return []
      
      const backups = JSON.parse(backupsStr)
      return backups.sort((a: any, b: any) => b.timestamp - a.timestamp)
    } catch (e) {
      return []
    }
  }

  // Função para deletar backup automático
  const deleteAutoBackup = (timestamp: number) => {
    try {
      const backups = getAutoBackups()
      const filtered = backups.filter((b: any) => b.timestamp !== timestamp)
      localStorage.setItem('nonato-auto-backups', JSON.stringify(filtered))
      return true
    } catch (e) {
      return false
    }
  }

  // Função para criar backup antes de operações críticas
  const createAutoBackupBeforeOperation = () => {
    try {
      createAutoBackup()
      // Também fazer backup do código automaticamente
      createAutoCodeBackup()
    } catch (error) {
      console.error('Erro ao criar backup antes da operação:', error)
    }
  }

  // Descarregar backup do código como ZIP para o PC (mais seguro: não perde mesmo que o servidor apague)
  const handleDownloadBackupZip = async () => {
    try {
      const response = await fetch('/api/backup-code/download', { method: 'GET' })
      if (!response.ok) {
        const err = await response.json().catch(() => ({}))
        throw new Error(err.error || 'Erro ao gerar ZIP')
      }
      const blob = await response.blob()
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `backup-codigo-${new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19)}.zip`
      document.body.appendChild(a)
      a.click()
      document.body.removeChild(a)
      URL.revokeObjectURL(url)
      alert('✓ ZIP descarregado. Guarde o ficheiro no seu PC para não perder o código.')
    } catch (error) {
      alert('❌ Erro ao descarregar backup: ' + (error as Error).message)
    }
  }

  // Função para criar backup AUTOMÁTICO do código do programa
  const handleBackupCodigo = async () => {
    try {
      const response = await fetch('/api/backup-code', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        }
      })

      const result = await response.json()

      if (response.ok) {
        const pathToShow = result.backupsFolderAbsolute || result.backupPath || result.backupsFolder || ''
        alert((t.codeBackupCreatedSuccess || '✓ BACKUP DO CÓDIGO CRIADO COM SUCESSO!\n\nPasta de backups: ' + pathToShow + '\n\nArquivos salvos: {count}\n\nAbra a pasta acima para ver o backup.').replace('{count}', String(result.filesCount)))
        loadCodeBackups()
      } else {
        throw new Error(result.error || 'Erro ao criar backup')
      }
    } catch (error) {
      alert('❌ ' + (t.errorCreatingCodeBackup || 'Erro ao criar backup do código') + ': ' + (error as Error).message)
      console.error('Erro no backup:', error)
    }
  }

  // Função para fazer backup automático antes de operações perigosas
  const createAutoCodeBackup = async () => {
    try {
      const response = await fetch('/api/backup-code', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        }
      })
      const result = await response.json()
      if (response.ok) {
        // Salvar também no localStorage como referência
        const backupInfo = {
          timestamp: new Date().toISOString(),
          path: result.backupPath,
          filesCount: result.filesCount
        }
        const existingBackups = JSON.parse(localStorage.getItem('nonato-code-backups') || '[]')
        existingBackups.unshift(backupInfo)
        // Manter apenas os últimos 10 backups
        if (existingBackups.length > 10) {
          existingBackups.splice(10)
        }
        localStorage.setItem('nonato-code-backups', JSON.stringify(existingBackups))
        // Atualizar lista de backups
        loadCodeBackups()
      }
    } catch (error) {
      console.error('Erro no backup automático:', error)
    }
  }

  // Função para carregar lista de backups disponíveis
  const loadCodeBackups = async () => {
    setLoadingBackups(true)
    try {
      const response = await fetch('/api/backup-code/list', {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
        }
      })
      const result = await response.json()
      if (response.ok) {
        setCodeBackups(result.backups || [])
        setCodeBackupsFolder(result.backupsFolder || '')
      } else {
        // Se a API não existir, tentar carregar do localStorage
        const localBackups = JSON.parse(localStorage.getItem('nonato-code-backups') || '[]')
        setCodeBackups(localBackups)
      }
    } catch (error) {
      // Em caso de erro, tentar carregar do localStorage
      const localBackups = JSON.parse(localStorage.getItem('nonato-code-backups') || '[]')
      setCodeBackups(localBackups)
      console.error('Erro ao carregar backups:', error)
    } finally {
      setLoadingBackups(false)
    }
  }

  // Função para restaurar código a partir de um backup
  const handleRestoreCodigo = async (backupPath: string) => {
    if (!window.confirm(t.restoreCodeConfirm || '⚠️ ATENÇÃO: Esta operação irá RESTAURAR o código do programa a partir do backup selecionado.\n\nTODOS os arquivos atuais serão substituídos pelos arquivos do backup.\n\nEsta ação NÃO PODE ser desfeita!\n\nDeseja continuar?')) {
      return
    }

    if (!window.confirm(t.restoreCodeFinalConfirm || '⚠️ CONFIRMAÇÃO FINAL:\n\nVocê tem CERTEZA que deseja restaurar o código?\n\nEsta operação é IRREVERSÍVEL e pode causar perda de dados se o backup estiver desatualizado.\n\nConfirma a restauração?')) {
      return
    }

    try {
      const response = await fetch('/api/backup-code/restore', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ backupPath })
      })

      const result = await response.json()

      if (response.ok) {
        alert((t.codeRestoredSuccess || '✓ CÓDIGO RESTAURADO COM SUCESSO!\n\nBackup restaurado: {path}\nArquivos restaurados: {count}\n\nA página será recarregada em 3 segundos para aplicar as mudanças.').replace('{path}', result.backupPath).replace('{count}', String(result.filesCount)))
        setTimeout(() => {
          window.location.reload()
        }, 3000)
      } else {
        throw new Error(result.error || 'Erro ao restaurar backup')
      }
    } catch (error) {
      alert((t.errorRestoringCode || 'Erro ao restaurar código: {error}. Verifique se o backup existe e se você tem permissões para restaurar arquivos.').replace('{error}', (error as Error).message))
      console.error('Erro na restauração:', error)
    }
  }

  // Restaurar código a partir de um ficheiro ZIP (backup descarregado para o PC)
  const handleRestoreFromZip = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0]
    if (!file) return
    if (!file.name.toLowerCase().endsWith('.zip')) {
      alert('Selecione um ficheiro .zip (backup do código).')
      event.target.value = ''
      return
    }
    if (!window.confirm('Restaurar o código a partir deste ZIP? Os ficheiros atuais (app, public, config) serão substituídos. Continuar?')) {
      event.target.value = ''
      return
    }
    setRestoringFromZip(true)
    try {
      const formData = new FormData()
      formData.append('file', file)
      const response = await fetch('/api/backup-code/restore-from-zip', {
        method: 'POST',
        body: formData,
      })
      const result = await response.json()
      if (response.ok) {
        alert('✓ ' + (result.message || `Restaurados ${result.filesCount} ficheiro(s). A página será recarregada.`))
        setTimeout(() => window.location.reload(), 2000)
      } else {
        throw new Error(result.error || 'Erro ao restaurar')
      }
    } catch (error) {
      alert('❌ Erro ao restaurar a partir do ZIP: ' + (error as Error).message)
    } finally {
      setRestoringFromZip(false)
      event.target.value = ''
    }
  }

  // Função para restaurar backup
  const handleRestoreBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) {
      alert(t.noBackupFile)
      return
    }

    if (!window.confirm(t.restoreConfirm + '\n\n' + t.restoreWarning)) {
      e.target.value = '' // Limpar o input
      return
    }

    const reader = new FileReader()
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string
        const backupData = JSON.parse(content)

        // Validar estrutura do backup
        if (!backupData.data || typeof backupData.data !== 'object') {
          throw new Error('Estrutura de backup inválida')
        }

        // Restaurar TODOS os dados
        if (backupData.data.logo !== null && backupData.data.logo !== undefined) {
          localStorage.setItem('nonato-logo', backupData.data.logo)
          setLogoUrl(backupData.data.logo)
        }

        if (backupData.data.logoType !== null && backupData.data.logoType !== undefined) {
          localStorage.setItem('nonato-logo-type', backupData.data.logoType)
          setLogoType(backupData.data.logoType as 'image' | 'video')
        }

        if (backupData.data.language) {
          localStorage.setItem('nonato-language', backupData.data.language)
          setSelectedLanguage(backupData.data.language)
        }

        if (backupData.data.users) {
          localStorage.setItem('nonato-users', backupData.data.users)
          setUsers(JSON.parse(backupData.data.users))
        }

        if (backupData.data.gestores) {
          localStorage.setItem('nonato-gestores', backupData.data.gestores)
          setGestores(JSON.parse(backupData.data.gestores))
        }

        if (backupData.data.tecnicos) {
          localStorage.setItem('nonato-tecnicos', backupData.data.tecnicos)
          setTecnicos(JSON.parse(backupData.data.tecnicos))
        }

        if (backupData.data.conhecimentoTecnicos) {
          localStorage.setItem('nonato-conhecimento-tecnicos', backupData.data.conhecimentoTecnicos)
          setConhecimentoTecnicos(JSON.parse(backupData.data.conhecimentoTecnicos))
        }

        if (backupData.data.equipamentos) {
          localStorage.setItem('nonato-equipamentos', backupData.data.equipamentos)
          setEquipamentos(JSON.parse(backupData.data.equipamentos))
        }

        if (backupData.data.clientes) {
          localStorage.setItem('nonato-clientes', backupData.data.clientes)
          setClientes(JSON.parse(backupData.data.clientes))
        }

        if (backupData.data.clientePrioritario) {
          localStorage.setItem('nonato-cliente-prioritario', backupData.data.clientePrioritario)
          setClientePrioritario(JSON.parse(backupData.data.clientePrioritario))
        }

        if (backupData.data.relatoriosServico) {
          localStorage.setItem('nonato-relatorios-servico', backupData.data.relatoriosServico)
          setRelatoriosServico(JSON.parse(backupData.data.relatoriosServico))
        }

        if (backupData.data.sidebarButtons) {
          localStorage.setItem('nonato-sidebar-buttons', backupData.data.sidebarButtons)
          setSidebarButtons(JSON.parse(backupData.data.sidebarButtons))
        }

        alert(t.restoreSuccess)
        
        // Recarregar a página para aplicar todas as mudanças
        window.location.reload()
      } catch (error) {
        alert(t.invalidBackupFile + ': ' + (error as Error).message)
        e.target.value = '' // Limpar o input
      }
    }

    reader.onerror = () => {
      alert(t.invalidBackupFile)
      e.target.value = '' // Limpar o input
    }

    reader.readAsText(file)
  }

