  const handleGrupoDesmontadoImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file && file.type.startsWith('image/')) {
      const reader = new FileReader()
      reader.onload = (event) => {
        const result = event.target?.result as string
        setGrupoDesmontadoForm({ ...grupoDesmontadoForm, imagem: result })
      }
      reader.readAsDataURL(file)
    }
  }

  const handleRemoveGrupoDesmontadoImage = () => {
    setGrupoDesmontadoForm({ ...grupoDesmontadoForm, imagem: '' })
  }

  const handlePecaDesmontadaImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files
    if (!files || files.length === 0) return

    const newImages: string[] = []
    Array.from(files).forEach((file) => {
      if (file.type.startsWith('image/')) {
        const reader = new FileReader()
        reader.onload = (event) => {
          const result = event.target?.result as string
          newImages.push(result)
          if (newImages.length === Array.from(files).filter(f => f.type.startsWith('image/')).length) {
            setPecaDesmontadaForm({ 
              ...pecaDesmontadaForm, 
              imagens: [...(pecaDesmontadaForm.imagens || []), ...newImages] 
            })
          }
        }
        reader.readAsDataURL(file)
      }
    })
  }

  const handleRemovePecaDesmontadaImage = (index: number) => {
    const newImages = [...(pecaDesmontadaForm.imagens || [])]
    newImages.splice(index, 1)
    setPecaDesmontadaForm({ ...pecaDesmontadaForm, imagens: newImages })
  }

