  const handleSaveFaturaFornecedor = () => {
    if (!selectedFornecedorForFatura || !faturaFornecedorForm.numeroFatura || !faturaFornecedorForm.mes || !faturaFornecedorForm.valor || !faturaFornecedorForm.clienteId) {
      alert(t.fillAllFields || 'Preencha todos os campos obrigatórios!')
      return
    }

    createAutoBackupBeforeOperation()

    const valor = faturaFornecedorForm.valor
    if (isNaN(valor) || valor <= 0) {
      alert(t.invalidValue || 'Valor inválido!')
      return
    }

    const cliente = clientes.find(c => c.id === faturaFornecedorForm.clienteId)
    if (!cliente) {
      alert(t.clientNotFound || 'Cliente não encontrado!')
      return
    }

    const updatedFornecedores = fornecedores.map(f => {
      if (f.id === selectedFornecedorForFatura.id) {
        if (editingFaturaFornecedor) {
          // Editar fatura existente
          const updatedFaturas = f.faturas.map(fat =>
            fat.id === editingFaturaFornecedor.id
              ? {
                  ...fat,
                  numeroFatura: faturaFornecedorForm.numeroFatura,
                  mes: faturaFornecedorForm.mes,
                  valor: valor,
                  clienteId: faturaFornecedorForm.clienteId,
                  clienteNome: cliente.nomeEmpresa,
                  dataVencimento: faturaFornecedorForm.dataVencimento || undefined,
                  status: faturaFornecedorForm.status,
                  observacoes: faturaFornecedorForm.observacoes || undefined
                }
              : fat
          )
          return { ...f, faturas: updatedFaturas }
        } else {
          // Adicionar nova fatura
          const newFatura: FaturaFornecedor = {
            id: Date.now().toString(),
            numeroFatura: faturaFornecedorForm.numeroFatura,
            mes: faturaFornecedorForm.mes,
            valor: valor,
            clienteId: faturaFornecedorForm.clienteId,
            clienteNome: cliente.nomeEmpresa,
            dataVencimento: faturaFornecedorForm.dataVencimento || undefined,
            status: faturaFornecedorForm.status,
            observacoes: faturaFornecedorForm.observacoes || undefined
          }
          return { ...f, faturas: [...(f.faturas || []), newFatura] }
        }
      }
      return f
    })

    setFornecedores(updatedFornecedores)
    localStorage.setItem('nonato-fornecedores', JSON.stringify(updatedFornecedores))

    setShowFaturaFornecedorForm(false)
    setFaturaFornecedorForm({
      numeroFatura: '',
      mes: new Date().toISOString().slice(0, 7),
      valor: 0,
      clienteId: '',
      clienteNome: '',
      dataVencimento: '',
      status: 'pendente',
      observacoes: ''
    })
    setEditingFaturaFornecedor(null)
    setSelectedFornecedorForFatura(null)
    alert(t.invoiceSavedSuccess || 'Fatura salva com sucesso!')
  }

