  const handleEquipamentoClientePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file || !file.type.startsWith('image/')) {
      alert(t.selectImage)
      return
    }
    const reader = new FileReader()
    reader.onload = (event) => {
      const result = event.target?.result as string
      setEquipamentoClienteForm({ ...equipamentoClienteForm, photo: result })
    }
    reader.readAsDataURL(file)
  }

