  const handlePhotoLibraryClienteChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files
    if (!files || files.length === 0) return
    const newPhotos: string[] = []
    Array.from(files).forEach((file) => {
      if (!file.type.startsWith('image/')) return
      const reader = new FileReader()
      reader.onload = (event) => {
        const result = event.target?.result as string
        newPhotos.push(result)
        if (newPhotos.length === Array.from(files).filter(f => f.type.startsWith('image/')).length) {
          setEquipamentoClienteForm({ 
            ...equipamentoClienteForm, 
            photoLibrary: [...(equipamentoClienteForm.photoLibrary || []), ...newPhotos] 
          })
        }
      }
      reader.readAsDataURL(file)
    })
  }

