  const handleDeleteRelatorio = (relatorioId: string) => {
    if (!selectedEquipamentoForRelatorio) return
    if (window.confirm((t as any).confirmDeleteRelatorio || 'Tem certeza que deseja excluir este relatório?')) {
      const cliente = clientes.find(c => c.id === selectedEquipamentoForRelatorio.cliente.id)
      if (cliente) {
        const equipamento = cliente.equipamentos[selectedEquipamentoForRelatorio.index]
        if (equipamento && equipamento.relatorios) {
          const relRemovido = equipamento.relatorios.find(r => r.id === relatorioId)
          if (relRemovido) {
            const nomePasta = (cliente.nomeEmpresa || 'Cliente').trim() || 'Cliente'
            const chavePasta = cliente.id
            const itemArq: ItemRelatorioExcluidoArquivo = {
              archiveId: `arch-nota-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`,
              excluidoEm: new Date().toISOString(),
              tipo: 'nota-equipamento',
              relatorio: JSON.parse(JSON.stringify(relRemovido)) as RelatorioEquipamento,
              equipamentoModelo: `${equipamento.modelo || ''} ${equipamento.marca || ''}`.trim(),
              equipamentoSerie: equipamento.numeroSerie
            }
            setRelatoriosExcluidosClientes(prev => {
              const pastas = { ...prev.pastas }
              const existente = pastas[chavePasta]
              const pasta: PastaRelatoriosExcluidosCliente = existente
                ? { ...existente, itens: [...existente.itens, itemArq] }
                : { clienteId: chavePasta, clienteNome: nomePasta, itens: [itemArq] }
              pastas[chavePasta] = pasta
              const next = { pastas }
              saveData('nonato-relatorios-excluidos-clientes', next)
              return next
            })
          }
          const updatedRelatorios = equipamento.relatorios.filter(r => r.id !== relatorioId)
          const updatedEquipamento = { ...equipamento, relatorios: updatedRelatorios }
          const updatedEquipamentos = [...cliente.equipamentos]
          updatedEquipamentos[selectedEquipamentoForRelatorio.index] = updatedEquipamento
          const updatedClientes = clientes.map(c => 
            c.id === cliente.id 
              ? { ...c, equipamentos: updatedEquipamentos }
              : c
          )
          setClientes(updatedClientes)
          saveData('nonato-clientes', updatedClientes)
          setSelectedEquipamentoForRelatorio({ ...selectedEquipamentoForRelatorio, equipamento: updatedEquipamento })
        }
      }
    }
  }

  const handleSaveRelatorio = () => {
    if (!selectedEquipamentoForRelatorio || !relatorioForm.titulo || !relatorioForm.conteudo) {
      alert(t.fillAllFields)
      return
    }

    const cliente = clientes.find(c => c.id === selectedEquipamentoForRelatorio.cliente.id)
    if (cliente) {
      const equipamento = cliente.equipamentos[selectedEquipamentoForRelatorio.index]
      if (equipamento) {
        const relatorios = equipamento.relatorios || []
        let updatedRelatorios: RelatorioEquipamento[]

        if (editingRelatorio) {
          updatedRelatorios = relatorios.map(r => 
            r.id === editingRelatorio.id
              ? { ...r, titulo: relatorioForm.titulo, conteudo: relatorioForm.conteudo }
              : r
          )
        } else {
          const newRelatorio: RelatorioEquipamento = {
            id: Date.now().toString(),
            titulo: relatorioForm.titulo,
            conteudo: relatorioForm.conteudo,
            dataGeracao: new Date().toLocaleString('pt-BR'),
            equipamentoId: equipamento.numeroSerie
          }
          updatedRelatorios = [...relatorios, newRelatorio]
        }

        const updatedEquipamento = { ...equipamento, relatorios: updatedRelatorios }
        const updatedEquipamentos = [...cliente.equipamentos]
        updatedEquipamentos[selectedEquipamentoForRelatorio.index] = updatedEquipamento
        const updatedClientes = clientes.map(c => 
          c.id === cliente.id 
            ? { ...c, equipamentos: updatedEquipamentos }
            : c
        )
        setClientes(updatedClientes)
        saveData('nonato-clientes', updatedClientes)
        setSelectedEquipamentoForRelatorio({ ...selectedEquipamentoForRelatorio, equipamento: updatedEquipamento })
        setShowRelatorioForm(false)
        setRelatorioForm({ titulo: '', conteudo: '' })
        setEditingRelatorio(null)
        alert((t as any).relatorioSaved || 'Relatório salvo com sucesso!')
      }
    }
  }

  // Função para gerar número automático de relatório no formato 123-0126
  const gerarNumeroRelatorio = (): string => {
    const hoje = new Date()
    const ano = hoje.getFullYear().toString().slice(-2) // Últimos 2 dígitos do ano
    const mes = String(hoje.getMonth() + 1).padStart(2, '0') // Mês com 2 dígitos
    const anoMes = `${mes}${ano}` // Formato: 0126 (mês + ano)
    
    // Usar o contador atual e incrementar
    const numeroSequencial = relatorioContador
    const novoContador = numeroSequencial + 1
    setRelatorioContador(novoContador)
    saveData('nonato-relatorio-contador', novoContador)
    
    return `${numeroSequencial}-${anoMes}`
  }

