      maquinaModelo: '',
      numeroMaquina: '',
      tipoServico: '',
      diasTrabalho: [],
      horasTrabalho: '',
      kmsPercorridos: '',
      horasViagem: '',
      servicoConcluido: false,
      retornoNecessario: false,
      entregaDocumentacao: false,
      liberacaoProducao: false,
      instrucaoFuncionarios: false,
      necessarioTrocaPecas: false,
      observacoes: '',
      pontosAberto: '',
