  const normalizeImportKey = (v: any): string =>
    String(v ?? '').trim().toLowerCase().replace(/\s+/g, ' ')

  // Mapeia objeto genérico (JSON do site) para PecaBiblioteca
  const mapItemToPecaBiblioteca = (item: any, index: number): PecaBiblioteca => {
    const codigo = String(item?.codigo ?? item?.code ?? item?.partNumber ?? item?.numero ?? item?.id ?? item?.ref ?? '')
    const nome = String(item?.nome ?? item?.name ?? item?.descricao ?? item?.description ?? item?.designation ?? '')
    const descricao = String(item?.descricao ?? item?.description ?? item?.designation ?? (nome || ''))
    const preco = item?.preco != null ? String(item.preco) : (item?.price != null ? String(item.price) : (item?.precoUnitario != null ? String(item.precoUnitario) : ''))
    return {
      id: item?.id && typeof item.id === 'string' ? item.id : `import-${Date.now()}-${index}-${Math.random().toString(36).slice(2, 9)}`,
      nome: nome || codigo || `Peça ${index + 1}`,
      codigo: codigo || `IMP-${index + 1}`,
      preco: preco || '',
      descricao: descricao || '',
      categoria: item?.categoria ?? item?.category ?? item?.grupo ?? '',
      categoriaId: item?.categoriaId ?? item?.categoryId ?? '',
      subcategoria: item?.subcategoria ?? item?.subcategory ?? '',
      subcategoriaId: item?.subcategoriaId ?? item?.subcategoryId ?? '',
      imagem: item?.imagem ?? item?.image ?? item?.img ?? '',
      dataCriacao: new Date().toISOString()
    }
  }

  const parseRawToPecas = useCallback((raw: string): PecaBiblioteca[] => {
    const trimRaw = raw.trim()
    let itens: any[] = []
    const pushIfValid = (obj: any) => {
      if (!obj || typeof obj !== 'object') return
      const maybeCodigo = String(obj?.codigo ?? obj?.code ?? obj?.partNumber ?? obj?.part_no ?? obj?.articleNumber ?? obj?.numero ?? obj?.id ?? obj?.ref ?? '').trim()
      const maybeNome = String(obj?.nome ?? obj?.name ?? obj?.descricao ?? obj?.description ?? obj?.designation ?? obj?.title ?? '').trim()
      if (maybeCodigo || maybeNome) itens.push(obj)
    }
    const csvSplit = (line: string, sep: string): string[] => {
      const out: string[] = []
      let cur = ''
      let quoted = false
      for (let i = 0; i < line.length; i++) {
        const ch = line[i]
        if (ch === '"') {
          if (quoted && line[i + 1] === '"') {
            cur += '"'
            i++
          } else {
            quoted = !quoted
          }
        } else if (ch === sep && !quoted) {
          out.push(cur)
          cur = ''
        } else {
          cur += ch
        }
      }
      out.push(cur)
      return out.map(v => v.trim())
    }

    if (trimRaw.startsWith('<')) {
      // Suporte a importação a partir de páginas HTML (tabelas/listas + JSON embutido em scripts)
      try {
        const parser = new DOMParser()
        const doc = parser.parseFromString(raw, 'text/html')

        // 1) Tentar tabelas HTML comuns
        const rows = Array.from(doc.querySelectorAll('table tr'))
        rows.forEach((row) => {
          const cells = Array.from(row.querySelectorAll('th,td')).map((c) => (c.textContent || '').trim())
          if (cells.length < 2) return
          const joined = cells.join(' ').toLowerCase()
          if (joined.includes('código') || joined.includes('codigo') || joined.includes('part') || joined.includes('refer') || joined.includes('preço') || joined.includes('preco') || joined.includes('descr')) {
            return // linha provável de cabeçalho
          }
          pushIfValid({
            codigo: cells[0] || '',
            nome: cells[1] || cells[0] || '',
            descricao: cells[2] || cells[1] || '',
            preco: cells.find(c => /(\d+[.,]\d{2})/.test(c)) || ''
          })
        })

        // 2) Tentar estruturas comuns em cards/listas de e-commerce
        if (itens.length === 0) {
          const cardSelectors = [
            '[data-part-number]',
            '[data-product-code]',
            '[data-sku]',
            '.product-item',
            '.product-card',
            '.slds-card'
          ]
          const cards = Array.from(doc.querySelectorAll(cardSelectors.join(',')))
          cards.forEach((card) => {
            const codeAttr =
              (card as HTMLElement).getAttribute('data-part-number') ||
              (card as HTMLElement).getAttribute('data-product-code') ||
              (card as HTMLElement).getAttribute('data-sku') ||
              ''
            const text = (card.textContent || '').replace(/\s+/g, ' ').trim()
            const mCode = text.match(/\b([A-Z0-9][A-Z0-9\-_.\/]{3,})\b/)
            const mPrice = text.match(/(\d{1,3}(?:[.\s]\d{3})*(?:[.,]\d{2})\s?(?:€|eur)?)/i)
            const titleEl = card.querySelector('h1,h2,h3,h4,.title,.name,[data-name],[data-title]')
            pushIfValid({
              codigo: codeAttr || (mCode ? mCode[1] : ''),
              nome: (titleEl?.textContent || '').trim() || text.slice(0, 140),
              descricao: text,
              preco: mPrice ? mPrice[1] : ''
            })
          })
        }

        // 3) Tentar scripts com JSON embutido
        if (itens.length === 0) {
          const scripts = Array.from(doc.querySelectorAll('script'))
          scripts.forEach((s) => {
            const txt = (s.textContent || '').trim()
            if (!txt) return
            // Captura candidatos JSON com chaves comuns de catálogo.
            const candidates = [
              ...(txt.match(/\{[\s\S]*?"(?:parts|items|products|pecas|data)"[\s\S]*?\}/gi) || []),
              ...(txt.match(/\[[\s\S]*?\]/g) || [])
            ]
            for (const candidate of candidates) {
              try {
                const parsed = JSON.parse(candidate)
                if (Array.isArray(parsed)) {
                  parsed.forEach(pushIfValid)
                } else if (parsed && typeof parsed === 'object') {
                  const arr =
                    (Array.isArray((parsed as any).pecas) && (parsed as any).pecas) ||
                    (Array.isArray((parsed as any).parts) && (parsed as any).parts) ||
                    (Array.isArray((parsed as any).items) && (parsed as any).items) ||
                    (Array.isArray((parsed as any).products) && (parsed as any).products) ||
                    (Array.isArray((parsed as any).data) && (parsed as any).data) ||
                    null
                  if (arr) arr.forEach(pushIfValid)
                }
              } catch {
                // ignorar trecho não-JSON
              }
            }
          })
        }
      } catch {
        // segue para retorno vazio caso não consiga analisar HTML
      }
    } else if (trimRaw.startsWith('[') || trimRaw.startsWith('{')) {
      const parsed = JSON.parse(raw)
      if (Array.isArray(parsed)) itens = parsed
      else if (parsed && typeof parsed === 'object' && (Array.isArray(parsed.pecas) || Array.isArray(parsed.parts) || Array.isArray(parsed.items) || Array.isArray(parsed.data)))
        itens = parsed.pecas ?? parsed.parts ?? parsed.items ?? parsed.data
      else itens = [parsed]
    } else {
      const lines = raw.split(/\r?\n/).filter((l: string) => l.trim())
      if (lines.length < 2) return []
      const sep = lines[0].includes(';') ? ';' : ','
      const headers = csvSplit(lines[0], sep).map((h: string) => h.trim().replace(/^["']|["']$/g, ''))
      for (let i = 1; i < lines.length; i++) {
        const vals = csvSplit(lines[i], sep).map((v: string) => v.trim().replace(/^["']|["']$/g, ''))
        const obj: Record<string, string> = {}
        headers.forEach((h, j) => { obj[h] = vals[j] ?? '' })
        itens.push(obj)
      }
    }
    // Normaliza e remove duplicados da própria importação.
    const mapped = itens.map((item, idx) => mapItemToPecaBiblioteca(item, idx))
    const seen = new Set<string>()
    return mapped.filter((p) => {
      const key = normalizeImportKey(p.codigo) || `n:${normalizeImportKey(p.nome)}`
      if (!key) return false
      if (seen.has(key)) return false
      seen.add(key)
      return true
    })
  }, [])

  const handleBuscarImportacaoUrl = useCallback(async () => {
    const url = urlImportacaoPecas.trim()
    const isHomagUrl = /shop\.homag\.com/i.test(url)
    const autoSelectGuiaPlataforma = () => {
      if (typeof navigator === 'undefined') return
      const ua = navigator.userAgent.toLowerCase()
      if (ua.includes('ipad') || (ua.includes('macintosh') && 'ontouchend' in document)) {
        setImportacaoGuiaPlataforma('ipad')
      } else if (ua.includes('android')) {
        setImportacaoGuiaPlataforma('android')
      } else {
        setImportacaoGuiaPlataforma('windows')
      }
    }
    if (!url) {
      setImportacaoUrlError(t?.importacaoUrlObrigatoria ?? 'Informe a URL da lista de peças.')
      return
    }
    if (!url.startsWith('http://') && !url.startsWith('https://')) {
      setImportacaoUrlError('A URL deve começar com http:// ou https://')
      return
    }
    setImportacaoUrlError(null)
    setImportacaoPreview(null)
    setImportacaoUrlLoading(true)

    const tryParseAndPreview = (raw: string): boolean => {
      try {
        const pecas = parseRawToPecas(raw)
        if (pecas.length === 0) return false
        setImportacaoPreview(pecas)
        setImportacaoUrlError(null)
        return true
      } catch {
        return false
      }
    }

    let apiError: string | null = null
    try {
      // 1) Tentar primeiro pela API do servidor (evita CORS; funciona para a maioria dos URLs)
      const res = await fetch('/api/import-from-url', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url })
      })
      const text = await res.text()
      let json: { ok?: boolean; error?: string; data?: string } = { ok: false }
      if (text.trim()) {
        try {
          json = JSON.parse(text)
        } catch {
          apiError = (t?.importacaoErroRespostaInvalida ?? 'Resposta inválida do servidor.') + (res.status ? ` (${res.status})` : '')
        }
      }
      if (!apiError && res.ok && json.ok && typeof json.data === 'string') {
        if (tryParseAndPreview(json.data)) {
          setImportacaoUrlLoading(false)
          return
        }
        setImportacaoUrlError(t?.importacaoErroJsonInvalido ?? 'O conteúdo da URL não é um JSON ou CSV válido.')
        if (isHomagUrl) {
          autoSelectGuiaPlataforma()
          setShowImportacaoGuiaHomag(true)
        }
        setImportacaoUrlLoading(false)
        return
      }
      if (!apiError) {
        if (!text.trim()) apiError = t?.importacaoErroRespostaVazia ?? 'O servidor respondeu sem dados.'
        else if (json?.error) apiError = json.error
        else apiError = t?.importacaoErroBusca ?? 'Erro ao buscar a URL.'
      }

      // 2) Se a API falhou (modo demo, 404, rota em falta após restauro, etc.), tentar buscar a URL diretamente no browser
      try {
        const directRes = await fetch(url, {
          method: 'GET',
          headers: { 'Accept': 'application/json, text/csv, text/plain, */*' },
          mode: 'cors'
        })
        if (directRes.ok) {
          const raw = await directRes.text()
          if (tryParseAndPreview(raw)) {
            setImportacaoUrlLoading(false)
            return
          }
        }
      } catch (_) {
        // Fallback direto falhou (ex.: CORS)
      }
      setImportacaoUrlError(String(apiError).toLowerCase().includes('fetch failed') ? (t?.importacaoErroFetchFailed ?? 'Não foi possível aceder à URL. Verifique o endereço e a ligação.') : apiError)
      if (isHomagUrl) {
        autoSelectGuiaPlataforma()
        setShowImportacaoGuiaHomag(true)
      }
    } catch (e: any) {
      // Falha ao chamar a API (rede, etc.) — tentar buscar a URL diretamente no browser
      try {
        const directRes = await fetch(url, {
          method: 'GET',
          headers: { 'Accept': 'application/json, text/csv, text/plain, */*' },
          mode: 'cors'
        })
        if (directRes.ok) {
          const raw = await directRes.text()
          if (tryParseAndPreview(raw)) {
            setImportacaoUrlLoading(false)
            return
          }
        }
      } catch (_) {}
      const msg = e?.message || String(e)
      const isNetwork = msg && String(msg).toLowerCase().includes('fetch failed')
      setImportacaoUrlError(isNetwork ? (t?.importacaoErroFetchFailed ?? 'Não foi possível aceder à URL. Verifique o endereço e a ligação.') : (msg || (t?.importacaoErroBusca ?? 'Erro ao buscar a URL.')))
      if (isHomagUrl) {
        autoSelectGuiaPlataforma()
        setShowImportacaoGuiaHomag(true)
      }
    } finally {
      setImportacaoUrlLoading(false)
    }
  }, [urlImportacaoPecas, t, parseRawToPecas])

  const handleImportacaoFicheiro = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return
    setImportacaoUrlError(null)
    setImportacaoPreview(null)
    const reader = new FileReader()
    reader.onload = () => {
      try {
        const raw = String(reader.result ?? '')
        const pecas = parseRawToPecas(raw)
        if (pecas.length === 0) {
          setImportacaoUrlError(t?.importacaoNenhumaLinha ?? 'Nenhuma lista encontrada no ficheiro. Use CSV (1ª linha = cabeçalhos) ou JSON.')
          return
        }
        setImportacaoPreview(pecas)
      } catch (err: any) {
        setImportacaoUrlError(err?.message || (t?.importacaoErroJsonInvalido ?? 'Ficheiro inválido. Use CSV ou JSON.'))
      }
    }
    reader.readAsText(file, 'UTF-8')
    e.target.value = ''
  }, [parseRawToPecas, t])

  const handleImportacaoColarTexto = useCallback(() => {
    const raw = importacaoTextoColado.trim()
    if (!raw) {
      setImportacaoUrlError(t?.importacaoUrlObrigatoria ?? 'Cole o conteúdo JSON ou CSV na caixa acima.')
      return
    }
    if (/^https?:\/\//i.test(raw)) {
      setImportacaoUrlError(
        t?.importacaoColarUrlNaoSuportado ??
        'Neste campo, cole o conteúdo JSON/CSV (não a URL). Para links, use "Buscar da URL".'
      )
      return
    }
    setImportacaoUrlError(null)
    setImportacaoPreview(null)
    try {
      const pecas = parseRawToPecas(raw)
      if (pecas.length === 0) {
        setImportacaoUrlError(t?.importacaoNenhumaLinha ?? 'Nenhuma lista encontrada. Use JSON (array ou objeto com .pecas/.parts/.items/.data) ou CSV (1ª linha = cabeçalhos).')
        return
      }
      setImportacaoPreview(pecas)
    } catch (err: any) {
      setImportacaoUrlError(err?.message || (t?.importacaoErroJsonInvalido ?? 'Conteúdo inválido. Use JSON ou CSV com cabeçalhos na primeira linha.'))
    }
  }, [importacaoTextoColado, parseRawToPecas, t])

  const handleAdicionarImportacaoPreview = useCallback(() => {
    if (!importacaoPreview || importacaoPreview.length === 0) return
    const existentes = pecasBiblioteca
    const existentesKeys = new Set(
      existentes.map((e) => normalizeImportKey(e.codigo) || `n:${normalizeImportKey(e.nome)}`)
    )
    const novos: PecaBiblioteca[] = []
    importacaoPreview.forEach((p, i) => {
      const key = normalizeImportKey(p.codigo) || `n:${normalizeImportKey(p.nome)}`
      if (!key || existentesKeys.has(key)) return
      existentesKeys.add(key)
      novos.push({
        ...p,
        id: `import-${Date.now()}-${i}-${Math.random().toString(36).slice(2, 9)}`,
        dataCriacao: new Date().toISOString()
      })
    })
    const atualizado = [...existentes, ...novos]
    setPecasBiblioteca(atualizado)
    localStorage.setItem('nonato-pecas-biblioteca', JSON.stringify(atualizado))
    setImportacaoPreview(null)
    setUrlImportacaoPecas('')
    if (novos.length === 0) {
      alert(t?.importacaoSemNovidades ?? 'Nenhuma peça nova para adicionar (itens já existentes na biblioteca).')
      return
    }
    alert(t?.importacaoSucesso ?? `${novos.length} peça(s) adicionada(s) à biblioteca.`)
  }, [importacaoPreview, pecasBiblioteca, t])

