                    e.currentTarget.style.backgroundColor = 'rgba(255, 165, 0, 0.35)'
                    e.currentTarget.style.borderColor = 'rgba(255, 165, 0, 0.9)'
                    e.currentTarget.style.boxShadow = '0 0 18px rgba(255, 165, 0, 0.5)'
                    e.currentTarget.style.transform = 'translateY(-2px)'
