                      <span style={{ fontSize: '20px' }}>{editingEquipamentoCliente ? '✏️' : '➕'}</span>
                      {editingEquipamentoCliente ? (safeT?.editarEquipamento || 'Editar Equipamento') : (safeT?.adicionarEquipamento || 'Adicionar Equipamento')}
